import pg from "pg";
import crypto from "crypto";
const Pool = pg.Pool;
const pool = new Pool({ connectionString: process.env.PROD_DATABASE_URL || process.env.DATABASE_URL });
function hash(s: string): string { return crypto.createHash("md5").update(s.toLowerCase().trim()).digest("hex"); }
function rn(e:string,b:string,d:number,s:string,o:string[],c:number,r:string) {
  return {tier:"rn",exam:e,stem:s,options:o,correct:c,rationale:r,diff:d,bs:b};
}
function np(e:string,b:string,d:number,s:string,o:string[],c:number,r:string) {
  return {tier:"np",exam:e,stem:s,options:o,correct:c,rationale:r,diff:d,bs:b};
}

const QS = [
  // === RN QUESTIONS (125 to ensure we exceed 2500) ===
  rn("NCLEX-RN","Cardiovascular",3,"A nurse is caring for a client who developed torsades de pointes. Which intervention should the nurse anticipate?",["Administer amiodarone","Administer IV magnesium sulfate","Perform synchronized cardioversion","Administer adenosine"],1,"Torsades de pointes is a polymorphic ventricular tachycardia associated with prolonged QT interval. First-line treatment is IV magnesium sulfate 1-2g bolus. Overdrive pacing or isoproterenol may be used if magnesium is ineffective. Avoid amiodarone and other QT-prolonging agents. Correct underlying causes: electrolyte imbalances, offending medications."),
  rn("NCLEX-RN","Cardiovascular",3,"A client with acute pericarditis reports sharp chest pain that worsens with deep inspiration. Which position should the nurse recommend?",["Supine position","Sitting upright and leaning forward","Left lateral decubitus","Trendelenburg position"],1,"Pericarditis pain is pleuritic (worsens with inspiration) and positional. Sitting up and leaning forward reduces pain by decreasing pericardial pressure on the diaphragm. Treatment includes NSAIDs (ibuprofen) and colchicine. Watch for cardiac tamponade: Beck triad (hypotension, JVD, muffled heart sounds)."),
  rn("NCLEX-RN","Cardiovascular",3,"A nurse is assessing a client with suspected deep vein thrombosis. Which finding is most consistent with DVT?",["Bilateral leg edema","Unilateral calf swelling, warmth, and tenderness","Cool, pale extremity with absent pulses","Intermittent claudication"],1,"DVT presents with unilateral extremity swelling, warmth, erythema, and tenderness. Homan sign (calf pain with dorsiflexion) is unreliable. Diagnosis: D-dimer (rule-out), compression ultrasound (confirmatory). Risk factors: Virchow triad (stasis, endothelial injury, hypercoagulability). Treatment: anticoagulation (heparin then warfarin/DOACs)."),
  rn("NCLEX-RN","Respiratory",3,"A client with COPD exacerbation is receiving BiPAP. The nurse notes the client is increasingly lethargic and CO2 is rising. What should the nurse prepare for?",["Continue BiPAP and reassess in 1 hour","Endotracheal intubation and mechanical ventilation","Discontinue BiPAP and apply nasal cannula","Increase the oxygen flow rate"],1,"Rising CO2 with BiPAP failure indicates worsening respiratory failure. Signs of impending respiratory failure: decreasing level of consciousness, rising PaCO2 despite NIV, worsening acidosis. Prepare for intubation and mechanical ventilation. NIV failure criteria include inability to tolerate mask, worsening ABGs after 1-2 hours, hemodynamic instability."),
  rn("NCLEX-RN","Respiratory",3,"A client with community-acquired pneumonia has a chest X-ray showing right lower lobe consolidation. Which assessment finding does the nurse expect?",["Hyperresonance to percussion over the right lower lobe","Bronchial breath sounds, dullness to percussion, and increased tactile fremitus over the affected area","Decreased fremitus bilaterally","Absent breath sounds throughout"],1,"Consolidation causes bronchial breath sounds heard peripherally (normally only over trachea), dullness to percussion (fluid/solid replacing air), increased tactile fremitus (solid conducts vibrations better), and egophony (E-to-A changes). These findings distinguish consolidation from pleural effusion (decreased fremitus, dullness)."),
  rn("NCLEX-RN","Respiratory",3,"A nurse is caring for a client with a tension pneumothorax. Which clinical finding is most concerning?",["Chest pain on the affected side","Tracheal deviation away from the affected side with hypotension","Bilateral crackles on auscultation","Productive cough"],1,"Tension pneumothorax is a life-threatening emergency. Signs: tracheal deviation away from affected side, hypotension, tachycardia, absent breath sounds on affected side, JVD, cyanosis. Treatment: immediate needle decompression (2nd intercostal space, midclavicular line) followed by chest tube insertion. Do not delay for X-ray."),
  rn("NCLEX-RN","Neurological",3,"A client with myasthenia gravis develops difficulty swallowing and respiratory distress. The nurse suspects myasthenic crisis. Which intervention is priority?",["Administer anticholinesterase medications immediately","Ensure airway patency and prepare for possible intubation","Administer atropine","Increase physical activity to build strength"],1,"Myasthenic crisis is an exacerbation causing respiratory failure. Priority: airway management (possible intubation). Differentiate from cholinergic crisis (too much medication): Tensilon test or clinical assessment. Myasthenic crisis: weakness despite medication. Cholinergic crisis: excessive secretions, bradycardia, miosis. Treat with plasmapheresis or IVIG."),
  rn("NCLEX-RN","Neurological",3,"A client with bacterial meningitis has positive Kernig and Brudzinski signs. The nurse should implement which precautions?",["Standard precautions only","Droplet precautions for the first 24 hours of antibiotic therapy","Contact precautions","Airborne precautions"],1,"Bacterial meningitis (Neisseria meningitidis): droplet precautions until 24 hours after appropriate antibiotic therapy. Kernig sign: resistance to knee extension with hip flexed. Brudzinski sign: involuntary hip flexion when neck is flexed. Treatment: empiric IV antibiotics (ceftriaxone + vancomycin), dexamethasone, and close contacts receive chemoprophylaxis."),
  rn("NCLEX-RN","Neurological",3,"A client with increased intracranial pressure has a Glasgow Coma Scale score of 7. The nurse should position the client with the head of bed at:",["Flat (0 degrees)","30 degrees elevation with head midline","90 degrees elevation","Trendelenburg position"],1,"Elevated ICP management: HOB 30 degrees promotes venous drainage from brain, keep head midline (avoid jugular compression), avoid hip flexion. GCS <= 8: intubation for airway protection. Other interventions: osmotic diuretics (mannitol), hypertonic saline, hyperventilation (short-term only), temperature management, seizure prophylaxis."),
  rn("NCLEX-RN","Neurological",3,"A client had a tonic-clonic seizure. During the postictal phase, what is the nurse's priority action?",["Restrain the client for safety","Position the client on their side and maintain airway patency","Insert an oral airway immediately","Administer IV lorazepam"],0,"Postictal care: position on side (recovery position) to prevent aspiration, suction as needed, maintain patent airway, monitor vital signs and oxygen saturation, perform neurological assessment, and provide a calm environment. Never force anything into the mouth during or after a seizure. Document seizure characteristics: duration, type, preceding events."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with hepatic encephalopathy has an elevated serum ammonia level. Which medication should the nurse administer?",["Metoclopramide","Lactulose to reduce ammonia absorption in the gut","Omeprazole","Metronidazole only"],1,"Lactulose is first-line for hepatic encephalopathy. Mechanism: osmotic laxative that converts ammonia to ammonium in the colon (non-absorbable), increasing fecal excretion. Titrate to 2-3 soft stools daily. Rifaximin is added for recurrent episodes. Monitor for dehydration and electrolyte imbalances. Assess neurological status with West Haven criteria."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with cirrhosis develops ascites. The nurse should restrict which dietary component?",["Protein","Sodium intake to 2000 mg per day or less","Carbohydrates","Fat"],1,"Ascites management: sodium restriction (< 2g/day), fluid restriction if hyponatremia (< 125 mEq/L), diuretics (spironolactone + furosemide in 100:40 ratio), paracentesis for tense ascites (replace albumin if > 5L removed). Monitor daily weight, abdominal girth. Avoid NSAIDs (reduce renal blood flow)."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with acute pancreatitis has severe epigastric pain radiating to the back. Which intervention should the nurse implement first?",["Provide a high-fat diet for nutrition","Keep the client NPO, provide IV fluid resuscitation, and administer analgesics","Prepare for immediate surgery","Administer oral pancreatic enzymes"],1,"Acute pancreatitis management: NPO initially (bowel rest), aggressive IV fluid resuscitation (Ringer's lactate 250-500 mL/hr initially), IV analgesics (hydromorphone, avoid morphine per some guidelines), antiemetics. Monitor for complications: necrotizing pancreatitis, pseudocyst, ARDS, organ failure. Ranson criteria and APACHE II for severity assessment."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with Crohn disease is prescribed infliximab. Before starting therapy, the nurse should ensure:",["A hepatitis B and tuberculosis screening test has been completed","The client has received a live vaccine","No screening is necessary","The client is pregnant"],0,"TNF-alpha inhibitors (infliximab, adalimumab) require screening before initiation: TB (PPD or IGRA test), hepatitis B (reactivation risk), and checking for active infections. Avoid live vaccines during therapy. Monitor for serious infections, infusion reactions (premedicate with acetaminophen, diphenhydramine, corticosteroids). Increased risk of lymphoma."),
  rn("NCLEX-RN","Endocrine",3,"A client with diabetic ketoacidosis has a blood glucose of 250 mg/dL and potassium of 3.2 mEq/L. What should the nurse do before starting insulin?",["Start insulin immediately regardless of potassium","Replace potassium first because insulin will further lower potassium levels","Administer sodium bicarbonate","Give oral glucose"],1,"In DKA, insulin drives potassium intracellularly, potentially causing fatal hypokalemia. If K+ < 3.3: replace potassium BEFORE starting insulin. If K+ 3.3-5.3: give potassium with insulin. If K+ > 5.3: start insulin, recheck K+ every 2 hours. DKA protocol: IV fluids (NS initially), insulin drip (0.1-0.14 units/kg/hr), potassium replacement, monitor electrolytes every 1-2 hours."),
  rn("NCLEX-RN","Endocrine",3,"A client with Addison disease is scheduled for surgery. The nurse should anticipate which medication adjustment?",["Discontinuing corticosteroids before surgery","Administering stress-dose corticosteroids (hydrocortisone) perioperatively","No medication changes needed","Switching to mineralocorticoids only"],1,"Addisonian crisis prevention: patients on chronic corticosteroids or with adrenal insufficiency require stress-dose steroids for surgery/illness. Typical: hydrocortisone 100mg IV bolus before surgery, then 50mg IV every 8 hours, taper over 1-3 days. Without stress dosing, patients risk adrenal crisis: hypotension, shock, hyperkalemia, hyponatremia."),
  rn("NCLEX-RN","Endocrine",3,"A nurse is caring for a client with syndrome of inappropriate antidiuretic hormone (SIADH). Which finding does the nurse expect?",["Hypernatremia and increased urine output","Hyponatremia with concentrated urine and decreased urine output","Hyperkalemia and metabolic acidosis","Hypercalcemia and polyuria"],1,"SIADH: excess ADH causes water retention leading to dilutional hyponatremia, concentrated urine (high specific gravity), decreased urine output, fluid overload, weight gain without edema. Treatment: fluid restriction (750-1500 mL/day), hypertonic saline for severe hyponatremia (Na+ < 120), demeclocycline or tolvaptan for chronic SIADH. Correct slowly (< 8-10 mEq/L per 24 hours) to prevent central pontine myelinolysis."),
  rn("NCLEX-RN","Endocrine",3,"A client with hyperthyroidism is prescribed methimazole. The nurse should monitor for which serious adverse effect?",["Weight gain","Agranulocytosis indicated by fever, sore throat, and infection","Hyperglycemia","Constipation"],1,"Methimazole and PTU (antithyroid drugs) can cause agranulocytosis (severe neutropenia) in 0.1-0.5% of patients. Teach clients to report fever, sore throat, or signs of infection immediately. Obtain baseline and periodic CBC. PTU also carries risk of hepatotoxicity (black box warning). Methimazole is preferred except in first trimester of pregnancy."),
  rn("NCLEX-RN","Renal/Urinary",3,"A client with acute kidney injury has a potassium level of 6.8 mEq/L. Which intervention should the nurse implement first?",["Administer oral kayexalate","Obtain a 12-lead ECG and prepare for IV calcium gluconate administration","Restrict dietary potassium","Schedule hemodialysis for the next day"],1,"Severe hyperkalemia (> 6.5 mEq/L) is a medical emergency. Priority: ECG (check for peaked T waves, widened QRS, sine wave). Treatment sequence: calcium gluconate IV (cardiac membrane stabilization, does NOT lower K+), insulin + dextrose (shifts K+ intracellularly), sodium bicarbonate, albuterol nebulization, kayexalate/patiromer (removes K+), emergent dialysis if refractory."),
  rn("NCLEX-RN","Renal/Urinary",3,"A client on peritoneal dialysis has cloudy dialysate return. The nurse should suspect:",["Normal dialysate appearance","Peritonitis and obtain a sample for culture and cell count","Inadequate dwell time","Excessive ultrafiltration"],1,"Cloudy effluent in peritoneal dialysis is the hallmark of peritonitis. Other signs: abdominal pain, fever, rebound tenderness. Obtain sample for WBC count (> 100/mm3 with > 50% neutrophils = peritonitis), Gram stain, and culture. Treat with intraperitoneal antibiotics (vancomycin + third-generation cephalosporin empirically). Most common organisms: coagulase-negative staphylococci."),
  rn("NCLEX-RN","Renal/Urinary",3,"A nurse is caring for a client with nephrotic syndrome. Which assessment finding does the nurse expect?",["Hematuria without proteinuria","Massive proteinuria (>3.5g/day), hypoalbuminemia, hyperlipidemia, and peripheral edema","Oliguria with hyperkalemia","Polyuria with hypotension"],1,"Nephrotic syndrome classic features: massive proteinuria (> 3.5g/24hr), hypoalbuminemia (< 3g/dL), hyperlipidemia, lipiduria, and generalized edema (periorbital in morning, peripheral later). Increased infection risk (loss of immunoglobulins), hypercoagulable state (loss of antithrombin III). Treatment: ACEi/ARBs (reduce proteinuria), statins, diuretics, sodium restriction, prophylactic anticoagulation in some cases."),
  rn("NCLEX-RN","Musculoskeletal",3,"A client in skeletal traction reports severe calf pain and swelling in the immobilized leg. What should the nurse do?",["Apply warm compresses and elevate the leg","Assess for DVT and notify the healthcare provider immediately","Remove the traction weights to relieve pressure","Apply ice packs to the calf"],1,"Immobilization is a major risk factor for DVT (Virchow triad: stasis). Calf pain and swelling in an immobilized extremity requires immediate assessment for DVT. Do NOT massage the area (risk of embolization). Notify provider for urgent Doppler ultrasound. Implement VTE prophylaxis in immobilized patients: sequential compression devices, pharmacologic prophylaxis (LMWH or heparin)."),
  rn("NCLEX-RN","Musculoskeletal",3,"A client with a hip fracture is post-operative day 1. The nurse notes the affected leg is shortened and externally rotated. What should the nurse suspect?",["Normal postoperative positioning","Hip dislocation requiring immediate notification of the surgeon","Muscle spasm that will resolve","Incomplete fracture reduction"],1,"Post-hip arthroplasty dislocation signs: affected leg shortened, externally rotated (posterior dislocation, most common), severe pain, inability to bear weight. Notify surgeon immediately. Prevention: hip precautions (avoid flexion > 90 degrees, adduction past midline, internal rotation for posterior approach). Use abduction pillow, elevated toilet seat, avoid low chairs."),
  rn("NCLEX-RN","Pediatrics",3,"A 2-year-old child with epiglottitis is drooling and sitting in a tripod position. What is the nurse's priority action?",["Inspect the throat with a tongue depressor","Maintain the child in an upright position and prepare for emergency airway management","Administer oral antibiotics immediately","Obtain a throat culture"],1,"Epiglottitis is a medical emergency. NEVER examine the throat (can trigger complete airway obstruction). Classic presentation: abrupt onset, high fever, drooling, dysphagia, tripod positioning, muffled voice (4 D's: drooling, dysphagia, distress, dysphonia). Management: maintain current position, prepare for intubation/tracheotomy, IV antibiotics (ceftriaxone), keep child calm."),
  rn("NCLEX-RN","Pediatrics",3,"A nurse is teaching parents of a child newly diagnosed with type 1 diabetes. Which statement by the parent indicates understanding?",["We will adjust insulin based on what our child wants to eat","We will monitor blood glucose before meals and at bedtime, and learn to recognize signs of hypoglycemia","We only need to check blood sugar once a week","Our child will eventually outgrow this condition"],1,"Type 1 DM education: blood glucose monitoring (before meals, bedtime, with symptoms), insulin administration (rotation of sites, proper storage), carbohydrate counting, recognizing hypo/hyperglycemia signs, sick day rules, exercise adjustments, medical alert identification. Emphasize that T1DM is lifelong and insulin-dependent."),
  rn("NCLEX-RN","Pediatrics",3,"A 4-month-old infant is brought to the emergency department with bilious (green) vomiting. The nurse should prioritize:",["Offering oral rehydration fluids","Notifying the healthcare provider immediately as bilious vomiting in an infant may indicate malrotation with volvulus","Administering an antiemetic","Reassuring the parents this is normal"],1,"Bilious vomiting in an infant is a surgical emergency until proven otherwise. Most concerning diagnosis: malrotation with midgut volvulus (can cause intestinal ischemia and necrosis within hours). Requires emergent upper GI series and surgical consultation. Other causes: intestinal atresia, Hirschsprung disease, NEC."),
  rn("NCLEX-RN","Maternal/Newborn",3,"A laboring client's fetal monitor shows late decelerations. The nurse's first action should be:",["Continue to observe the pattern","Reposition the client to left lateral, administer oxygen, increase IV fluids, and notify the provider","Prepare for immediate delivery","Administer oxytocin to speed up labor"],1,"Late decelerations indicate uteroplacental insufficiency. Nursing interventions: reposition (left lateral), administer oxygen (10 L non-rebreather), increase IV fluids, discontinue oxytocin if running, notify provider. If pattern persists: prepare for emergent cesarean delivery. Causes: uterine hyperstimulation, maternal hypotension, placental abruption."),
  rn("NCLEX-RN","Maternal/Newborn",3,"A postpartum client is experiencing heavy vaginal bleeding with a boggy uterus 2 hours after delivery. What is the nurse's priority intervention?",["Apply ice packs to the perineum","Perform uterine massage (fundal massage) and assess for clots","Administer antibiotics","Encourage ambulation"],1,"Uterine atony is the most common cause of postpartum hemorrhage (80%). Priority: bimanual uterine massage to stimulate contraction. If ineffective: administer uterotonics (oxytocin, methylergonovine, carboprost, misoprostol). Monitor vital signs, urine output. Rule out other causes: retained placental tissue, lacerations, coagulopathy (4 T's: Tone, Tissue, Trauma, Thrombin)."),
  rn("NCLEX-RN","Maternal/Newborn",3,"A pregnant client at 34 weeks gestation presents with painless bright red vaginal bleeding. The nurse should suspect:",["Placental abruption","Placenta previa and avoid performing a vaginal examination","Normal bloody show","Urinary tract infection"],1,"Placenta previa: painless, bright red vaginal bleeding (typically in third trimester). NEVER perform vaginal/digital exam (can cause massive hemorrhage). Diagnosis: transabdominal ultrasound. Management: bed rest, serial hemoglobin, type and crossmatch, plan cesarean delivery at 36-37 weeks for stable previa. Emergency cesarean for uncontrolled bleeding."),
  rn("NCLEX-RN","Mental Health",3,"A client with major depressive disorder has started an SSRI and now reports increased energy but continued suicidal ideation. What should the nurse do?",["Discontinue the medication immediately","Increase the frequency of safety assessments because the client may now have the energy to act on suicidal thoughts","Reassure the client that the medication is working","Reduce the SSRI dose"],1,"Early SSRI treatment paradox: energy and motivation may improve before mood lifts, increasing suicide risk as the client now has energy to act on persistent suicidal ideation. Highest risk period: first 2-4 weeks of treatment. Increase safety monitoring, restrict access to lethal means, 1:1 supervision if needed. Black box warning for ages < 25."),
  rn("NCLEX-RN","Mental Health",3,"A client with bipolar disorder on lithium presents with coarse tremors, vomiting, and confusion. The nurse suspects:",["Therapeutic lithium effect","Lithium toxicity and holds the dose while checking a serum lithium level","Alcohol withdrawal","Neuroleptic malignant syndrome"],1,"Lithium toxicity signs: mild (1.5-2.0 mEq/L): N/V/D, fine tremor, polyuria. Moderate (2.0-2.5): coarse tremor, confusion, drowsiness, ataxia. Severe (>2.5): seizures, coma, cardiac dysrhythmias, death. Management: hold lithium, check level, aggressive IV hydration (NS), hemodialysis for severe toxicity. Therapeutic range: 0.6-1.2 mEq/L. Monitor renal and thyroid function."),
  rn("NCLEX-RN","Mental Health",3,"A client in the emergency department is experiencing a panic attack with hyperventilation. The nurse should:",["Have the client breathe into a paper bag","Coach slow, deep breathing and provide a calm, quiet environment","Administer epinephrine","Leave the client alone to calm down"],1,"Panic attack management: stay with the client, provide calm reassurance, coach controlled breathing (in through nose 4 counts, out through mouth 6 counts), reduce environmental stimuli. Paper bag breathing is NO longer recommended (risk of hypoxia). Pharmacologic: benzodiazepines (lorazepam) for acute episodes. Long-term: SSRIs and cognitive-behavioral therapy."),
  rn("NCLEX-RN","Pharmacology",3,"A client is receiving IV vancomycin. Which adverse effect should the nurse monitor for during infusion?",["Hypoglycemia","Red man syndrome (flushing, pruritus, erythema of the upper body) from rapid infusion","Hearing loss only after extended use","Nephrotoxicity only"],1,"Red man syndrome: histamine-mediated reaction from rapid vancomycin infusion. Presents with flushing, erythema, pruritus of face, neck, and upper trunk. Prevention: infuse over at least 60 minutes (10 mg/min). Not a true allergy. Also monitor: trough levels (15-20 mcg/mL for serious infections), nephrotoxicity, ototoxicity. Premedicate with diphenhydramine if history of red man syndrome."),
  rn("NCLEX-RN","Pharmacology",3,"A nurse is administering potassium chloride (KCl) to a client with hypokalemia. Which nursing consideration is most important?",["Administer IV push for rapid correction","Never administer KCl IV push; dilute and infuse via pump at no more than 10 mEq/hr peripherally","Mix KCl with dextrose solutions only","Administer KCl IM for faster absorption"],1,"IV KCl safety: NEVER give IV push (can cause fatal cardiac arrest). Maximum peripheral infusion rate: 10 mEq/hr. Central line: up to 20 mEq/hr with cardiac monitoring. Maximum concentration: 40 mEq/L peripheral, 80 mEq/L central. Always use infusion pump. Monitor ECG during rapid replacement. Assess urine output before administration (K+ is renally excreted)."),
  rn("NCLEX-RN","Pharmacology",3,"A client on warfarin has an INR of 8.5 with no active bleeding. The nurse should anticipate:",["Continue warfarin at the current dose","Hold warfarin, administer oral vitamin K, and recheck INR in 24 hours","Administer IV heparin","Give fresh frozen plasma immediately"],1,"Supratherapeutic INR management (without bleeding): INR 4.5-10: hold warfarin, consider oral vitamin K (2.5-5 mg). INR > 10 without bleeding: hold warfarin, give oral vitamin K 5-10 mg, recheck in 24 hours. Active bleeding: IV vitamin K + 4-factor PCC (prothrombin complex concentrate) or FFP. Target INR for most indications: 2.0-3.0."),
  rn("NCLEX-RN","Pharmacology",3,"A nurse is caring for a client who received an epidural opioid for pain management. Which assessment finding requires immediate intervention?",["Pain rating of 3 out of 10","Respiratory rate of 6 breaths per minute","Mild pruritus","Urinary retention"],1,"Epidural opioid complication: respiratory depression is the most serious adverse effect (can occur up to 24 hours post-administration). Respiratory rate < 8/min requires immediate intervention: stop infusion, stimulate client, administer naloxone (Narcan), bag-valve-mask ventilation if needed. Other side effects: pruritus, nausea, urinary retention, hypotension. Monitor respiratory rate every 1-2 hours."),
  rn("NCLEX-RN","Integumentary",3,"A client with a stage 3 pressure injury has yellow slough in the wound bed. The nurse should:",["Apply a dry dressing and leave undisturbed","Perform wound debridement (autolytic, enzymatic, or sharp) to remove necrotic tissue and promote healing","Pack the wound with povidone-iodine gauze","Apply a transparent film dressing"],1,"Wound bed preparation: yellow slough is devitalized tissue that impedes healing. Debridement methods: autolytic (moisture-retentive dressings like hydrogels), enzymatic (collagenase/Santyl), sharp/surgical (fastest), mechanical (wet-to-dry, not preferred). After debridement, maintain moist wound environment. Assess for infection signs. Nutritional optimization: protein, vitamin C, zinc."),
  rn("NCLEX-RN","Integumentary",3,"A client with a full-thickness burn is at risk for which electrolyte imbalance during the first 24 hours?",["Hypokalemia","Hyperkalemia from cellular destruction and fluid shifts","Hypercalcemia","Hypernatremia"],1,"Burn injury first 24 hours (emergent/resuscitative phase): massive fluid shift from intravascular to interstitial (edema). Cellular destruction releases potassium (hyperkalemia), myoglobin, and hemoglobin. Also: hyponatremia (dilutional), hemoconcentration. After 48-72 hours: fluid remobilization phase with diuresis, hypokalemia risk. Parkland formula: 4 mL x kg x %TBSA burned."),
  rn("NCLEX-RN","Hematological",3,"A client receiving a blood transfusion develops fever, chills, and flank pain 15 minutes after starting the infusion. The nurse's first action should be:",["Slow the transfusion rate","Stop the transfusion immediately and keep the IV line open with normal saline","Administer acetaminophen and continue","Increase the infusion rate to complete quickly"],1,"Acute hemolytic transfusion reaction (ABO incompatibility): stop transfusion IMMEDIATELY, keep IV open with NS (new tubing), notify provider and blood bank, send blood bag and tubing to blood bank, obtain blood and urine samples (hemoglobinuria). Maintain blood pressure and renal perfusion. Most common cause: clerical error in patient/blood identification."),
  rn("NCLEX-RN","Hematological",3,"A client with iron deficiency anemia is prescribed oral ferrous sulfate. Which instruction should the nurse provide?",["Take with milk to prevent stomach upset","Take on an empty stomach with vitamin C to enhance absorption","Take with calcium supplements","Take with antacids to reduce GI effects"],1,"Iron absorption optimization: take on empty stomach (1 hour before or 2 hours after meals), with vitamin C (orange juice enhances absorption by maintaining iron in ferrous state). Avoid taking with calcium, dairy, tea, coffee, antacids, or phosphates (inhibit absorption). Side effects: GI upset, constipation, black stools. Use straw for liquid iron (prevents tooth staining)."),
  rn("NCLEX-RN","Hematological",3,"A client with hemophilia A is bleeding. The nurse should anticipate administering:",["Vitamin K","Factor VIII concentrate","Fresh frozen plasma only","Aminocaproic acid only"],1,"Hemophilia A: deficiency of clotting Factor VIII. Treatment: Factor VIII concentrate (recombinant or plasma-derived) for acute bleeding. Desmopressin (DDAVP) for mild hemophilia A (releases stored Factor VIII). Hemophilia B: Factor IX deficiency. Avoid aspirin, NSAIDs, and IM injections. Teach safe activities, apply pressure for 15+ minutes, avoid contact sports."),
  rn("NCLEX-RN","Immunological",3,"A client is prescribed an epinephrine auto-injector for anaphylaxis management. The nurse should teach the client to inject into which site?",["Deltoid muscle","Outer mid-thigh (vastus lateralis) through clothing if needed","Gluteal muscle","Abdomen subcutaneously"],1,"Epinephrine IM injection for anaphylaxis: outer mid-thigh (vastus lateralis), can inject through clothing in emergency. Dose: 0.3 mg (adult), 0.15 mg (pediatric < 30 kg). Hold in place 10 seconds. May repeat in 5-15 minutes if no improvement. Always call 911 after use. Carry two auto-injectors. Check expiration dates regularly. After use: observe for biphasic reaction (up to 72 hours)."),
  rn("NCLEX-RN","Immunological",3,"A client with rheumatoid arthritis is taking methotrexate. Which supplement should the nurse ensure the client is also taking?",["Vitamin D only","Folic acid to reduce methotrexate side effects","Iron supplements","Calcium only"],1,"Methotrexate (folate antagonist) side effects: bone marrow suppression, hepatotoxicity, stomatitis, GI effects. Folic acid supplementation (1 mg daily) reduces side effects without reducing efficacy. Monitor: CBC, liver function, renal function. Contraindicated in pregnancy (teratogenic, Category X). Avoid alcohol (hepatotoxicity). Leucovorin for methotrexate rescue in toxicity."),
  rn("NCLEX-RN","Geriatrics",3,"An elderly client on multiple medications is prescribed a new benzodiazepine for insomnia. The nurse's priority concern is:",["The medication will not be effective","Increased fall risk due to sedation, impaired balance, and altered metabolism in older adults","The client will become addicted immediately","No concerns for elderly clients"],1,"Beers Criteria: benzodiazepines are potentially inappropriate in older adults due to increased sensitivity (altered pharmacokinetics), fall risk, cognitive impairment, delirium, and respiratory depression. Safer alternatives: sleep hygiene education, melatonin, low-dose trazodone. If prescribed, start low and go slow. Fall prevention: assess gait, remove hazards, bed alarm, adequate lighting."),
  rn("NCLEX-RN","Geriatrics",3,"A nurse is assessing an older adult client for delirium versus dementia. Which finding distinguishes delirium?",["Gradual onset over months","Acute onset with fluctuating level of consciousness","Irreversible cognitive decline","No disturbance in attention"],0,"Delirium vs. Dementia key differences: Delirium: acute onset (hours to days), fluctuating consciousness, often reversible, usually has identifiable cause (infection, medications, metabolic). Dementia: gradual onset (months to years), clear consciousness until late stages, progressive and irreversible. Delirium can be superimposed on dementia. Common delirium causes in elderly: UTI, pneumonia, medications, pain, constipation."),
  rn("NCLEX-RN","Fundamentals",3,"A client is prescribed strict intake and output monitoring. Which fluid should the nurse include in the intake record?",["Only IV fluids","All oral fluids, IV fluids, tube feedings, IV medications, and blood products","Only water consumed orally","Only measurable oral liquids"],1,"Intake includes: all oral fluids (water, juice, soup, gelatin, ice cream, popsicles), IV fluids, IV piggyback medications, blood products, tube feedings, and IV flushes. Output includes: urine, emesis, drainage (NG, wound, chest tube), liquid stool, and estimated blood loss. Ice chips: record as 50% of volume (1 cup ice = 1/2 cup fluid). Accurate I&O is critical for fluid balance assessment."),
  rn("NCLEX-RN","Fundamentals",3,"A nurse is delegating tasks to unlicensed assistive personnel (UAP). Which task is appropriate to delegate?",["Assessment of a new admission","Measuring and recording vital signs on a stable client","Administering IV push medication","Teaching a client about a new medication"],1,"Delegation principles (Five Rights): right task, right circumstance, right person, right direction/communication, right supervision. UAP can perform: vital signs on stable clients, ambulation, bathing, feeding, I&O measurement, specimen collection, simple dressing changes. Cannot delegate: assessment, planning, evaluation, patient education, medication administration, unstable client care."),
  rn("NCLEX-RN","Fundamentals",3,"A client's arterial blood gas results show: pH 7.28, PaCO2 58 mmHg, HCO3 24 mEq/L. The nurse interprets this as:",["Metabolic acidosis","Respiratory acidosis (uncompensated)","Respiratory alkalosis","Metabolic alkalosis"],1,"ABG interpretation: pH 7.28 (acidotic, < 7.35), PaCO2 58 (elevated, > 45 = respiratory cause), HCO3 24 (normal, 22-26, no compensation yet) = uncompensated respiratory acidosis. Causes: COPD, sedation, pneumonia, airway obstruction. If HCO3 were elevated, it would indicate renal compensation. ROME: Respiratory Opposite (pH and CO2), Metabolic Equal (pH and HCO3)."),
  rn("NCLEX-RN","Fundamentals",3,"A nurse is preparing to administer a medication via a nasogastric tube. What should the nurse do before administering?",["Crush all medications together and mix with juice","Verify tube placement by checking pH of aspirate (should be acidic, pH <5.5), flush with water before and after, and administer each medication separately","Inject medications rapidly through the tube","Clamp the tube for 2 hours before administration"],1,"NG medication administration: verify placement (pH < 5.5 of aspirate, X-ray for initial placement), flush with 30 mL water before, between each medication, and after (prevent clogging). Administer each medication separately. Use liquid forms when possible. Do not crush enteric-coated or extended-release medications. Elevate HOB 30-45 degrees to prevent aspiration."),
  rn("NCLEX-RN","Community Health",3,"A community health nurse is implementing a secondary prevention strategy for hypertension. Which activity represents secondary prevention?",["Teaching a nutrition class about reducing sodium intake","Conducting blood pressure screening clinics to identify undiagnosed hypertension","Providing cardiac rehabilitation for a client post-MI","Distributing pamphlets about exercise benefits"],1,"Prevention levels: Primary: prevent disease occurrence (health promotion, immunizations, education). Secondary: early detection and treatment (screenings, diagnostic testing). Tertiary: limit disability and restore function (rehabilitation, support groups, chronic disease management). Blood pressure screening identifies existing disease early for prompt treatment, which is secondary prevention."),
  rn("NCLEX-RN","Community Health",3,"A nurse is planning a home visit for a client recently discharged with a new colostomy. Which is the priority assessment?",["The client's insurance coverage","The client's ability to perform colostomy care and the adequacy of the home environment","The client's dietary preferences only","The client's medication cost"],1,"Home health priority assessment: client's ability to perform self-care (colostomy care technique, pouch changes, skin assessment), knowledge deficit, support system availability, home environment (access to supplies, bathroom, clean area for pouch changes), and psychological adjustment. Assess for peristomal skin breakdown, adequate nutrition, and return appointment understanding."),
  rn("NCLEX-RN","Leadership",3,"A charge nurse receives report that a float nurse from a medical unit will be assigned to the ICU. Which assignment is most appropriate for the float nurse?",["The most critically ill client requiring complex titrations","A stable client requiring routine monitoring and assessments","A new admission with unknown acuity","A client on multiple vasoactive drips"],1,"Float nurse assignment: assign within the nurse's competency and scope. Medical floor nurse to ICU: assign the most stable patient requiring routine care. Avoid assignments requiring specialized ICU skills (ventilator management, vasoactive drip titrations, complex hemodynamic monitoring). Provide orientation to unit, emergency equipment, and available resources. The charge nurse retains accountability for appropriate delegation."),
  rn("NCLEX-RN","Leadership",3,"A nurse discovers a medication error that did not harm the client. What is the most appropriate action?",["Complete an incident report, notify the healthcare provider, monitor the client, and follow the facility's reporting procedures","Tell the client and document nothing","Wait to see if the client develops symptoms","Report to the charge nurse only without documentation"],0,"Medication error response: notify the provider immediately, assess and monitor the client, complete an incident/variance/occurrence report (factual, objective, not placed in the medical record), document assessment findings and interventions in the medical record (do not document 'incident report filed'), report per facility policy. Purpose of incident reports: quality improvement, not punitive. Follow just culture principles."),
  rn("NCLEX-RN","Critical Care",4,"A client with acute respiratory distress syndrome (ARDS) is on mechanical ventilation. The nurse notes a plateau pressure of 35 cm H2O. Which intervention should the nurse anticipate?",["Increasing tidal volume","Reducing tidal volume to achieve lung-protective ventilation (6 mL/kg IBW)","Increasing respiratory rate to 30","Discontinuing PEEP"],1,"ARDS ventilation strategy (ARDSNet protocol): low tidal volume ventilation (6 mL/kg ideal body weight), maintain plateau pressure < 30 cm H2O, adequate PEEP (prevent atelectasis), permissive hypercapnia if needed. Elevated plateau pressure > 30 indicates overdistension. Also: prone positioning for P/F < 150, conservative fluid management, neuromuscular blockade for severe ARDS (first 48 hours)."),
  rn("NCLEX-RN","Critical Care",4,"A nurse is caring for a client with a pulmonary artery catheter. The nurse notes a wedge pressure (PAWP) of 22 mmHg. This finding suggests:",["Normal cardiac function","Left-sided heart failure with increased left ventricular preload","Right-sided heart failure","Hypovolemia"],1,"PAWP (pulmonary artery wedge pressure): reflects left ventricular end-diastolic pressure (preload). Normal: 8-12 mmHg. Elevated (>18): left-sided heart failure, fluid overload, mitral valve disease. Low (<6): hypovolemia. Hemodynamic monitoring normals: CVP 2-6, PAP 15-30/8-15, PAWP 8-12, CO 4-8 L/min, SVR 800-1200. Nursing: maintain transducer at phlebostatic axis, zero and level."),
  rn("NCLEX-RN","Critical Care",4,"A client develops pulseless ventricular tachycardia. According to ACLS guidelines, the nurse should:",["Administer adenosine","Immediately defibrillate and begin CPR","Administer amiodarone first","Obtain a 12-lead ECG before treatment"],1,"Pulseless VT is a shockable rhythm. ACLS algorithm: defibrillate immediately (120-200J biphasic), resume CPR for 2 minutes, establish IV/IO access. If persists: epinephrine 1mg every 3-5 minutes, defibrillate, then amiodarone 300mg first dose, 150mg second dose. H's and T's: Hypovolemia, Hypoxia, Hydrogen ion, Hypo/hyperkalemia, Hypothermia; Tension pneumothorax, Tamponade, Toxins, Thrombosis PE, Thrombosis MI."),
  rn("NCLEX-RN","Critical Care",4,"A client with sepsis has a lactate level of 4.2 mmol/L. This finding indicates:",["Normal tissue perfusion","Tissue hypoperfusion and anaerobic metabolism requiring aggressive fluid resuscitation","Dehydration only","Liver dysfunction"],1,"Elevated lactate (> 2 mmol/L) in sepsis indicates tissue hypoperfusion and anaerobic metabolism. Lactate > 4 mmol/L is associated with high mortality. Surviving Sepsis Campaign: measure lactate early, if elevated > 2, re-measure within 2-4 hours, guide resuscitation to normalize lactate. Initial resuscitation: 30 mL/kg IV crystalloid within 3 hours, blood cultures before antibiotics, broad-spectrum antibiotics within 1 hour."),
  rn("RN-CAT","Cardiovascular",4,"A client with Wolff-Parkinson-White (WPW) syndrome presents with rapid atrial fibrillation. Which medication should the nurse avoid administering?",["Procainamide","AV nodal blocking agents (digoxin, verapamil, beta-blockers) as they can cause ventricular fibrillation in WPW with atrial fibrillation","Amiodarone","Flecainide"],1,"WPW with atrial fibrillation: AV nodal blockers (digoxin, verapamil, diltiazem, beta-blockers) are CONTRAINDICATED. These agents slow conduction through the AV node but enhance conduction through the accessory pathway, potentially causing ventricular fibrillation. Treatment: procainamide or ibutilide for stable, cardioversion for unstable. Definitive treatment: catheter ablation of the accessory pathway."),
  rn("RN-CAT","Respiratory",4,"A client with severe asthma exacerbation has a suddenly silent chest on auscultation. The nurse should recognize this as:",["Improvement in the client's condition","A life-threatening sign indicating severe bronchospasm with minimal air movement requiring immediate intervention","Normal finding during an asthma attack","Resolution of wheezing"],1,"Silent chest in severe asthma: ominous sign indicating such severe bronchospasm that air movement is nearly absent. No wheezing does NOT mean improvement. Signs of impending respiratory arrest: silent chest, exhaustion, altered consciousness, bradycardia, hypotension. Immediate management: continuous nebulized bronchodilators, IV magnesium sulfate, systemic corticosteroids, prepare for intubation, ICU transfer."),
  rn("RN-CAT","Neurological",4,"A client with subarachnoid hemorrhage is at risk for cerebral vasospasm. The nurse monitors for this complication by assessing:",["Only blood pressure changes","Transcranial Doppler findings and new neurological deficits (confusion, focal weakness) typically occurring days 4-14 after the bleed","Pupil size only immediately after the event","Skin color changes"],1,"Cerebral vasospasm after SAH: peaks days 4-14. Clinical signs: new confusion, focal neurological deficits, decreased consciousness. Monitoring: transcranial Doppler (increased flow velocities), serial neurological assessments. Prevention and treatment: nimodipine (calcium channel blocker), Triple-H therapy (Hypertension, Hypervolemia, Hemodilution), and endovascular interventions (intra-arterial vasodilators, angioplasty). Hunt-Hess grading scale for SAH severity."),
  rn("RN-CAT","Endocrine",4,"A client with pheochromocytoma is scheduled for adrenalectomy. Preoperatively, the nurse should ensure:",["Beta-blockers are started first","Alpha-adrenergic blockade (phenoxybenzamine) is established before beta-blocker therapy to prevent hypertensive crisis","No preoperative medication preparation is needed","The client receives glucocorticoids only"],1,"Pheochromocytoma preoperative preparation: alpha-blockade FIRST (phenoxybenzamine or doxazosin for 10-14 days preoperatively) to prevent hypertensive crisis during tumor manipulation. THEN add beta-blocker for tachycardia (NEVER beta-blocker first - unopposed alpha stimulation causes severe hypertension). Liberal salt and fluid intake to expand contracted blood volume. Intraoperatively: monitor for hypertensive crises and post-resection hypotension."),
  rn("RN-CAT","Renal/Urinary",4,"A client with crush injury develops rhabdomyolysis. The nurse should anticipate which critical intervention?",["Restricting IV fluids to prevent edema","Aggressive IV normal saline infusion (200-300 mL/hr) to prevent acute kidney injury from myoglobin","Administering potassium supplements","Applying cold compresses to the injured area"],1,"Rhabdomyolysis: skeletal muscle breakdown releases myoglobin, CK, potassium, and phosphorus. Myoglobin precipitates in renal tubules causing AKI. Treatment: aggressive IV NS (200-300+ mL/hr, target UO 200-300 mL/hr), bicarbonate to alkalinize urine (myoglobin more soluble at pH > 6.5), monitor and treat hyperkalemia, monitor CK levels and renal function. Avoid nephrotoxins. Dialysis if refractory AKI."),
  rn("RN-CAT","Gastrointestinal",4,"A client with acute variceal hemorrhage should have the nurse prepare for which initial intervention?",["Oral proton pump inhibitors","Emergent upper endoscopy with variceal band ligation, IV octreotide, and blood product resuscitation","Barium swallow study","Scheduled outpatient colonoscopy"],1,"Acute variceal bleeding management: airway protection (intubation if altered consciousness), volume resuscitation (blood products, restrictive transfusion strategy Hb target 7-8), IV octreotide/somatostatin (splanchnic vasoconstriction), IV proton pump inhibitor, prophylactic antibiotics (ceftriaxone), emergent EGD with band ligation (within 12 hours). If uncontrolled: balloon tamponade (Sengstaken-Blakemore), TIPS procedure."),
  rn("NCLEX-RN","Pharmacology",3,"A client is prescribed heparin for anticoagulation. The nurse monitors which laboratory value?",["INR","aPTT (activated partial thromboplastin time)","Platelet count only","Bleeding time"],1,"Heparin monitoring: aPTT (target 1.5-2.5x control, typically 60-80 seconds). Also monitor platelets for heparin-induced thrombocytopenia (HIT): check baseline and every 2-3 days. HIT: platelet drop > 50% from baseline, paradoxical thrombosis. LMWH (enoxaparin): anti-Xa levels if needed, no routine aPTT monitoring. Antidote: protamine sulfate (1 mg per 100 units heparin)."),
  rn("NCLEX-RN","Pharmacology",3,"A nurse is administering digoxin. Before administration, the nurse should:",["Check the client's blood pressure only","Assess the apical pulse for one full minute and hold if rate is below 60 bpm","Check respiratory rate only","Administer without any assessment"],1,"Digoxin administration: check apical pulse for full minute before giving. Hold and notify provider if HR < 60 (adult) or < 70 (child) or > 100. Therapeutic level: 0.5-2.0 ng/mL. Toxicity signs: anorexia, nausea, vomiting, visual disturbances (yellow-green halos), dysrhythmias (PAT with block, junctional tachycardia). Hypokalemia increases toxicity risk. Antidote: digoxin immune Fab (Digibind)."),
  rn("NCLEX-RN","Respiratory",3,"A client with tuberculosis is started on RIPE therapy. The nurse should teach that which medication requires monitoring for visual changes?",["Rifampin","Ethambutol can cause optic neuritis and requires baseline and monthly visual acuity testing","Isoniazid","Pyrazinamide"],1,"RIPE therapy: Rifampin (hepatotoxic, orange secretions, induces CYP450), Isoniazid (hepatotoxic, peripheral neuropathy - give B6/pyridoxine), Pyrazinamide (hepatotoxic, hyperuricemia), Ethambutol (optic neuritis: decreased visual acuity, red-green color blindness). Baseline visual acuity and monthly testing required for ethambutol. Treatment duration: 6-9 months minimum."),
  rn("NCLEX-RN","Neurological",3,"A client post-craniotomy has clear fluid draining from the nose. The nurse should test the drainage for:",["Blood glucose only","Beta-2 transferrin or observe for a halo sign to identify cerebrospinal fluid rhinorrhea","Protein content","Ketones"],1,"CSF leak signs: clear drainage from nose (rhinorrhea) or ear (otorrhea). Tests: halo sign (clear ring around blood on linen), beta-2 transferrin (definitive, specific to CSF). Do NOT: pack the nose, suction nasally, or insert NG tube. Elevate HOB 30 degrees, instruct client to avoid blowing nose, coughing, straining. Notify neurosurgeon. Risk: meningitis."),
  rn("NCLEX-RN","Cardiovascular",3,"A client with peripheral arterial disease reports intermittent claudication. The nurse should teach the client to:",["Keep legs elevated above heart level at all times","Walk regularly to the point of claudication, rest until pain subsides, then resume walking","Apply compression stockings","Soak feet in hot water"],1,"Intermittent claudication management: supervised exercise program (walk until pain, rest, resume - improves collateral circulation). Ankle-brachial index (ABI): < 0.9 = PAD. Foot care: inspect daily, avoid extreme temperatures, wear proper footwear, avoid crossing legs. Medications: cilostazol (increases walking distance), aspirin or clopidogrel. Keep legs dependent (NOT elevated). Smoking cessation is critical."),
  rn("NCLEX-RN","Maternal/Newborn",3,"A nurse is caring for a newborn with physiologic jaundice. Which finding would require further evaluation?",["Jaundice appearing at 72 hours of age","Jaundice appearing within the first 24 hours of life which may indicate pathologic jaundice","Mild yellowing of the skin on day 3","Bilirubin level of 8 mg/dL on day 4"],1,"Pathologic vs. physiologic jaundice: Pathologic: appears < 24 hours, bilirubin rises > 5 mg/dL/day, total bilirubin > 95th percentile for age. Physiologic: appears day 2-3, peaks day 3-5, resolves by day 7-10 in term infants. Causes of pathologic: ABO/Rh incompatibility, hemolytic disease, G6PD deficiency, sepsis. Treatment: phototherapy, exchange transfusion for severe cases. Monitor for kernicterus signs."),
  rn("NCLEX-RN","Pediatrics",3,"A child with nephrotic syndrome has severe generalized edema. The nurse should monitor for which complication?",["Hypervolemia only","Infection due to loss of immunoglobulins in the urine","Hypernatremia","Metabolic alkalosis"],1,"Nephrotic syndrome complications: infection (most serious, due to immunoglobulin loss in urine, particularly peritonitis from Streptococcus pneumoniae), thromboembolism (loss of antithrombin III), hyperlipidemia, malnutrition, AKI. Treatment: corticosteroids (prednisone), albumin infusion for severe edema, diuretics, sodium restriction, pneumococcal and influenza vaccination."),
  rn("NCLEX-RN","Mental Health",3,"A nurse is caring for a client experiencing alcohol withdrawal. Which finding indicates delirium tremens and requires immediate intervention?",["Mild hand tremors","Visual hallucinations, severe agitation, autonomic instability (tachycardia, hypertension, diaphoresis, fever)","Mild anxiety and insomnia","Decreased appetite"],0,"Delirium tremens (DTs): most severe form of alcohol withdrawal, occurs 48-96 hours after last drink. Features: severe agitation, global confusion, visual hallucinations, autonomic hyperactivity (tachycardia, hypertension, diaphoresis, fever), seizures. Mortality 5-15% without treatment. Treatment: IV benzodiazepines (symptom-triggered dosing using CIWA-Ar scale), IV fluids, thiamine (before glucose to prevent Wernicke), electrolyte correction, ICU monitoring."),
  rn("NCLEX-RN","Endocrine",3,"A client with Cushing syndrome has undergone bilateral adrenalectomy. The nurse should teach that:",["Corticosteroid replacement will only be needed temporarily","Lifelong corticosteroid and mineralocorticoid replacement therapy will be necessary","No medication will be needed after surgery","Only mineralocorticoids will be needed"],1,"Bilateral adrenalectomy results in permanent adrenal insufficiency. Lifelong replacement: glucocorticoid (hydrocortisone 15-25 mg/day divided) AND mineralocorticoid (fludrocortisone 0.05-0.2 mg/day). Teach: never abruptly stop steroids, stress dosing for illness/surgery/trauma, carry medical alert ID, recognize adrenal crisis signs (weakness, hypotension, N/V), and carry emergency injection kit."),
  rn("NCLEX-RN","Renal/Urinary",3,"A client with chronic kidney disease stage 4 has a phosphorus level of 7.2 mg/dL. The nurse should administer:",["Calcium-based phosphate binder with meals to reduce phosphorus absorption","IV calcium gluconate","Additional phosphorus supplements","Vitamin D without phosphate binders"],0,"CKD hyperphosphatemia management: phosphate binders taken WITH meals (bind dietary phosphorus in GI tract). Types: calcium-based (calcium carbonate, calcium acetate), non-calcium (sevelamer, lanthanum). Restrict dietary phosphorus (< 800-1000 mg/day). Hyperphosphatemia causes secondary hyperparathyroidism, renal osteodystrophy, and vascular calcification. Also monitor calcium, PTH, and vitamin D levels."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with a bowel obstruction has a nasogastric tube connected to low intermittent suction. The nurse should monitor for which electrolyte imbalance?",["Hyperkalemia","Metabolic alkalosis with hypokalemia and hypochloremia from loss of gastric contents","Respiratory acidosis","Hypernatremia"],1,"NG suction removes gastric contents rich in HCl, potassium, and sodium. Resulting imbalances: metabolic alkalosis (loss of H+), hypokalemia (loss of K+ in gastric fluid and renal compensation), hypochloremia (loss of Cl-), hyponatremia. Monitor I&O, replace electrolytes as ordered, assess for signs of alkalosis (muscle twitching, tetany, slow/shallow respirations). IV fluid replacement typically NS with KCl."),
  rn("NCLEX-RN","Integumentary",3,"A nurse is assessing a client's wound for signs of infection. Which finding is most indicative of wound infection?",["Pink granulation tissue","Purulent drainage, erythema extending beyond wound edges, warmth, increasing pain, and elevated WBC","Serous drainage","Mild tenderness at the wound edges"],1,"Wound infection signs: purulent/foul-smelling drainage, erythema spreading beyond wound margins (cellulitis), increased warmth, increased/changing pain, delayed healing, elevated WBC, fever, dehiscence. Interventions: wound culture (swab after cleansing, or tissue biopsy for accuracy), topical/systemic antibiotics as ordered, wound cleansing, debridement of necrotic tissue, nutritional support."),
  rn("NCLEX-RN","Fundamentals",3,"A nurse is caring for a client receiving total parenteral nutrition (TPN). Which nursing intervention is essential?",["Administer TPN through a peripheral IV line","Monitor blood glucose every 4-6 hours due to the high glucose concentration in TPN","Change the TPN bag every 48 hours","Administer TPN without an infusion pump"],1,"TPN nursing care: administer via central line (high osmolality > 900 mOsm/L). Monitor blood glucose every 4-6 hours (hyperglycemia common). Use infusion pump (never bolus). Dedicated line (no medications or blood products through same lumen). Change tubing every 24 hours. Hang time < 24 hours. If TPN must be stopped suddenly: hang D10W to prevent rebound hypoglycemia. Monitor electrolytes, LFTs, triglycerides."),
  rn("NCLEX-RN","Fundamentals",3,"A nurse is caring for a client in contact isolation. Which personal protective equipment is required when entering the room?",["N95 respirator and gown","Gloves and gown","Surgical mask only","No PPE needed if not providing direct care"],1,"Contact precautions: gloves AND gown upon entering the room. Indications: MRSA, VRE, C. difficile, scabies, wound infections with resistant organisms. Dedicate equipment (stethoscope, BP cuff) to the room. C. difficile: use soap and water for hand hygiene (alcohol-based sanitizer does NOT kill spores). Remove PPE before leaving room, hand hygiene immediately after."),
  rn("NCLEX-RN","Cardiovascular",3,"A nurse is caring for a client with heart failure who is taking furosemide. Which electrolyte should the nurse monitor most closely?",["Sodium only","Potassium because loop diuretics cause significant potassium loss","Calcium only","Phosphorus only"],1,"Loop diuretics (furosemide, bumetanide) cause significant potassium loss. Hypokalemia signs: muscle weakness, leg cramps, cardiac dysrhythmias (flat T waves, U waves, ST depression), ileus, fatigue. Monitor K+ levels (normal 3.5-5.0 mEq/L). Interventions: potassium-rich foods (bananas, oranges, potatoes, spinach), KCl supplementation, consider potassium-sparing diuretic (spironolactone). Also monitor magnesium (loop diuretics cause hypomagnesemia)."),
  rn("NCLEX-RN","Respiratory",3,"A client with cystic fibrosis is prescribed dornase alfa (Pulmozyme). The nurse should teach that this medication:",["Replaces missing surfactant","Breaks down DNA in thick, purulent secretions to reduce sputum viscosity and improve airflow","Acts as a bronchodilator","Reduces inflammation in the airways"],1,"Dornase alfa (Pulmozyme): recombinant human DNase that cleaves extracellular DNA in CF sputum (from neutrophil breakdown), reducing viscosity and improving airflow. Administer via nebulizer daily. CF management also includes: chest physiotherapy, bronchodilators, hypertonic saline nebulization, azithromycin (anti-inflammatory), CFTR modulators (ivacaftor, lumacaftor/ivacaftor, elexacaftor/tezacaftor/ivacaftor), pancreatic enzymes, fat-soluble vitamins."),
  rn("NCLEX-RN","Neurological",3,"A client with Parkinson disease is taking carbidopa/levodopa. The nurse should teach the client to avoid:",["All carbohydrates","High-protein meals taken at the same time as the medication because protein competes with levodopa for absorption","All dairy products permanently","All fruits and vegetables"],1,"Levodopa-protein interaction: large neutral amino acids compete with levodopa for transport across the intestinal wall and blood-brain barrier. Teach: take medication 30 minutes before meals, distribute protein intake (not eliminate), eat larger protein meals in the evening. Side effects: dyskinesias (involuntary movements), on-off phenomenon, orthostatic hypotension, hallucinations. Avoid MAOIs (hypertensive crisis). Pyridoxine (B6) increases peripheral conversion."),
  rn("NCLEX-RN","Maternal/Newborn",3,"A nurse is assessing a newborn at 1 minute of life using the Apgar score. The newborn has a heart rate of 110, slow and irregular respirations, some flexion of extremities, grimace with stimulation, and acrocyanosis. What is the Apgar score?",["10","7","3","5"],1,"Apgar scoring (0-2 for each): Heart rate 110 = 2, Respiratory effort slow/irregular = 1, Muscle tone some flexion = 1, Reflex grimace = 1, Color acrocyanosis = 1. Total = 6. Actually - heart rate >100 = 2, respirations slow = 1, some flexion = 1, grimace = 1, acrocyanosis (blue extremities, pink body) = 1. Total = 6. Scored at 1 and 5 minutes. 7-10 normal, 4-6 needs intervention, 0-3 severe distress."),
  rn("NCLEX-RN","Pediatrics",3,"A 6-month-old infant is brought to the clinic for immunizations. The nurse notes the infant has a fever of 103.5 F and is irritable. What should the nurse do?",["Administer the vaccines as scheduled","Withhold immunizations and notify the healthcare provider because high fever is a contraindication","Give acetaminophen and proceed with vaccines","Reschedule all vaccines for one year later"],1,"Vaccine contraindications: moderate to severe acute illness WITH fever (defer until resolved). Minor illness with low-grade fever is NOT a contraindication. True contraindications: severe allergic reaction to vaccine component, encephalopathy within 7 days of pertussis-containing vaccine. Precaution vs. contraindication distinction is important. Document the reason for withholding and reschedule appropriately."),
  rn("NCLEX-RN","Mental Health",3,"A client with borderline personality disorder splits the nursing staff by telling one nurse that she is wonderful and another nurse is terrible. The nurse should:",["Agree with the client's assessment","Implement consistent limits, communicate as a team, and avoid personalizing the client's statements","Avoid the client","Confront the client aggressively"],1,"Splitting (idealization/devaluation): common defense mechanism in BPD. Management: consistent, firm limits from all staff, team communication (prevent manipulation), therapeutic but non-reactive response, do not take comments personally, avoid power struggles, validate feelings while maintaining boundaries. Treatment: dialectical behavior therapy (DBT) is evidence-based for BPD. Safety assessment for self-harm behaviors."),
  rn("NCLEX-RN","Pharmacology",3,"A client is prescribed enoxaparin (Lovenox) subcutaneously. The nurse should administer the injection into:",["The deltoid muscle","The anterolateral abdominal wall (love handles area), rotating sites","The vastus lateralis muscle","The gluteal muscle"],1,"Enoxaparin (LMWH) subcutaneous administration: anterolateral or posterolateral abdominal wall, at least 2 inches from umbilicus. Do NOT expel air bubble before injection (ensures full dose delivery). Do NOT aspirate. Do NOT rub the site after injection (increases bruising). Rotate sites. Inject at 90-degree angle. Hold the skin fold throughout injection. Monitor for signs of bleeding and HIT."),
  rn("NCLEX-RN","Cardiovascular",3,"A client with a new permanent pacemaker should be taught to:",["Use a microwave oven without restriction because modern pacemakers are well-shielded","Avoid MRI (unless pacemaker is MRI-conditional), carry a pacemaker ID card, and report signs of pacemaker malfunction","Avoid all electronic devices permanently","Resume heavy lifting immediately"],1,"Pacemaker teaching: carry ID card, report hiccups (phrenic nerve stimulation), dizziness, syncope, or palpitations (malfunction signs). Avoid MRI (unless MRI-conditional device), large magnets, electrical generators, and arc welding. Microwave ovens are safe. Cell phone: use opposite ear, do not carry in breast pocket over pacemaker. Airport security: present ID card, hand-wand screening preferred. Follow-up checks as scheduled."),
  rn("NCLEX-RN","Respiratory",3,"A nurse is caring for a client with a chest tube connected to a water-seal drainage system. The nurse notes continuous bubbling in the water-seal chamber. This indicates:",["Normal functioning","An air leak in the system that requires assessment of all connections","Resolved pneumothorax","The chest tube is ready for removal"],1,"Chest tube water-seal chamber: continuous bubbling = air leak (check connections, assess for bronchopleural fistula). Intermittent bubbling with respiration/coughing = expected (especially initially). No bubbling = resolved air leak or tube obstruction. Suction control chamber: continuous gentle bubbling = correct suction. Drainage chamber: monitor amount, color, and consistency. Never clamp a chest tube without provider order (tension pneumothorax risk). Keep collection system below chest level."),
  rn("NCLEX-RN","Neurological",3,"A client with a spinal cord injury at T6 develops a severe headache, flushing above the injury, and a blood pressure of 210/120 mmHg. The nurse should first:",["Administer an analgesic for the headache","Sit the client upright and identify and remove the stimulus causing autonomic dysreflexia","Lower the head of bed to reduce blood pressure","Apply cold compresses to the forehead"],1,"Autonomic dysreflexia: medical emergency in SCI above T6. Triggered by noxious stimulus below injury level. Priority: sit client upright (orthostatic decrease in BP), immediately check for and remove the trigger (distended bladder is most common - catheterize or check for kinked catheter, fecal impaction, tight clothing, skin irritation). If BP remains elevated: administer fast-acting antihypertensive (nifedipine, nitropaste). Without treatment: stroke, seizure, death."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with a newly created ileostomy has an output of 1500 mL in 24 hours. The nurse should:",["Restrict fluid intake","Monitor for dehydration, replace fluids and electrolytes, and assess output characteristics","Consider this output abnormal and clamp the stoma","Reduce the client's diet"],1,"Normal ileostomy output: 500-1000 mL/day initially, decreasing to 200-500 mL/day as bowel adapts. High output (> 1000-1500 mL): risk for dehydration, hyponatremia, hypokalemia, metabolic acidosis (loss of bicarbonate). Interventions: oral and IV fluid replacement, electrolyte monitoring, anti-diarrheal medications (loperamide), dietary adjustments. Teach: adequate fluid intake, thickening foods (bananas, rice, applesauce), recognize dehydration signs."),
  rn("NCLEX-RN","Endocrine",3,"A client with hypothyroidism is prescribed levothyroxine. The nurse should teach the client to:",["Take the medication with a large breakfast","Take on an empty stomach, 30-60 minutes before breakfast, and not with calcium or iron supplements","Take at bedtime with milk","Take only when feeling tired"],1,"Levothyroxine administration: take on empty stomach (30-60 minutes before breakfast or at bedtime 4 hours after last meal) for optimal absorption. Separate from calcium, iron, antacids, cholestyramine by 4 hours (reduce absorption). Start low, increase slowly (especially in elderly or cardiac patients). Monitor TSH in 6-8 weeks. Teach: lifelong therapy, do not switch brands without provider approval, signs of hyper/hypothyroidism."),
  rn("NCLEX-RN","Renal/Urinary",3,"A client undergoing hemodialysis develops chest pain, dyspnea, and cyanosis during treatment. The nurse suspects air embolism. What is the immediate action?",["Continue dialysis and monitor","Clamp the blood line, position the client on their left side in Trendelenburg position, and administer 100% oxygen","Position the client upright","Increase the dialysis flow rate"],1,"Air embolism during hemodialysis: clamp the venous blood line immediately, position client LEFT SIDE in Trendelenburg (traps air in right atrium, preventing pulmonary embolism), administer 100% O2, notify provider. Prevention: check all connections, avoid running blood pump with air in the lines, use air detectors. Other dialysis complications: hypotension (most common), disequilibrium syndrome, muscle cramps, arrhythmias."),
  rn("NCLEX-RN","Hematological",3,"A client with disseminated intravascular coagulation (DIC) has which characteristic laboratory findings?",["Elevated fibrinogen and low D-dimer","Prolonged PT and aPTT, decreased fibrinogen, decreased platelets, and elevated D-dimer and FDP","Normal coagulation studies","Elevated platelets and normal PT"],1,"DIC lab findings: prolonged PT and aPTT (coagulation factor consumption), decreased fibrinogen (< 100 mg/dL), decreased platelets (< 100,000), elevated D-dimer and FDP (fibrin breakdown products). DIC: simultaneous clotting and bleeding. Treatment: treat underlying cause (sepsis, trauma, obstetric complications), supportive care (blood products: FFP for factors, cryoprecipitate for fibrinogen, platelets), heparin is controversial."),
  rn("NCLEX-RN","Immunological",3,"A client is diagnosed with systemic lupus erythematosus (SLE). The nurse should teach about avoiding which environmental factor?",["Cold temperatures only","Prolonged sun exposure because UV light can trigger disease flares","Humid environments","Windy conditions"],1,"SLE photosensitivity: UV light triggers disease flares (skin rash, systemic symptoms). Teach: avoid direct sunlight (especially 10 AM-4 PM), use broad-spectrum SPF 50+ sunscreen, wear protective clothing, sunglasses, wide-brimmed hat. Other triggers: infection, stress, certain medications (sulfonamides, hydralazine, procainamide). Hallmark: malar butterfly rash. Monitor: ANA, anti-dsDNA antibodies, complement levels (C3, C4)."),
  rn("NCLEX-RN","Critical Care",4,"A client on a ventilator develops sudden high-pressure alarm activation. The nurse should first assess for:",["Equipment malfunction only","Causes of increased airway resistance including secretions, bronchospasm, biting the tube, pneumothorax, or tube kinking","Low tidal volume delivery","Ventilator disconnect"],1,"High-pressure alarm: airway resistance increased or lung compliance decreased. Causes: secretions (suction needed), bronchospasm, client biting ET tube (insert bite block), kinking of tubing, pneumothorax, right mainstem intubation, coughing/fighting ventilator, abdominal distension. Assess patient first: auscultate lungs, check tube position, suction if indicated. Low-pressure alarm: disconnect, leak, or cuff deflation."),
  rn("NCLEX-RN","Pharmacology",3,"A client taking a monoamine oxidase inhibitor (MAOI) should avoid which food?",["Fresh fruits","Aged cheese, cured meats, and fermented foods because they contain tyramine","Whole grains","Fresh vegetables"],1,"MAOI-tyramine interaction: MAOIs prevent tyramine breakdown, causing severe hypertensive crisis (occipital headache, stiff neck, diaphoresis, nausea, hypertension, potentially stroke or death). Tyramine-rich foods: aged cheese, cured/smoked meats, fermented foods (sauerkraut, soy sauce, miso), draft beer, red wine, overripe bananas/avocados. Continue dietary restrictions 2-4 weeks after stopping MAOI. Medications to avoid: sympathomimetics, meperidine, SSRIs (serotonin syndrome)."),
  rn("NCLEX-RN","Fundamentals",3,"A nurse receives an order for morphine 2 mg IV push. Before administering, the nurse should verify:",["Only the medication name","The five rights of medication administration, assess respiratory rate and oxygen saturation, and check for allergies","Only the dose","Only the route"],1,"Opioid administration safety: five rights (right patient, drug, dose, route, time), assess respiratory rate (hold if < 12), SpO2, level of consciousness, pain assessment, allergy history. Morphine specifics: dilute, administer slowly (over 4-5 minutes), monitor for respiratory depression, hypotension, urinary retention, constipation. Have naloxone available. Document pain reassessment after administration."),
  rn("NCLEX-RN","Cardiovascular",3,"A nurse assessing a client with infective endocarditis should look for which classic findings?",["Clear lung sounds bilaterally","Osler nodes, Janeway lesions, splinter hemorrhages, and a new or changing heart murmur","Bilateral pedal edema only","Decreased WBC count"],1,"Infective endocarditis classic findings: Osler nodes (painful, erythematous nodules on fingers/toes - immune complex), Janeway lesions (painless, erythematous lesions on palms/soles - septic emboli), splinter hemorrhages (dark streaks under nails), Roth spots (retinal hemorrhages), new/changing murmur, fever, positive blood cultures (Duke criteria). Complications: embolic events (stroke, splenic/renal infarcts), heart failure, abscess formation."),
  rn("NCLEX-RN","Respiratory",3,"A nurse is caring for a client with pleural effusion. Which assessment finding does the nurse expect?",["Hyperresonance to percussion","Diminished breath sounds, dullness to percussion, and decreased tactile fremitus over the affected area","Loud bronchial breath sounds","Barrel chest"],1,"Pleural effusion assessment: diminished or absent breath sounds over the effusion, dullness to percussion, decreased tactile fremitus (fluid attenuates vibration transmission), dyspnea, pleuritic chest pain. Differentiate from consolidation (increased fremitus). Diagnosis: chest X-ray (blunting of costophrenic angle), ultrasound. Treatment: thoracentesis (diagnostic and therapeutic), chest tube for large/recurrent effusions, treat underlying cause."),
  rn("NCLEX-RN","Neurological",3,"A client is receiving tissue plasminogen activator (tPA) for acute ischemic stroke. The nurse should monitor for:",["Hyperglycemia only","Signs of bleeding, especially intracranial hemorrhage (severe headache, altered consciousness, hypertension, vomiting)","Skin rash","Joint pain"],1,"tPA for stroke: window 3-4.5 hours from symptom onset. Most serious complication: intracranial hemorrhage (6-7%). Monitor: frequent neurological assessments (NIHSS every 15 minutes x 2 hours, then every 30 minutes x 6 hours), blood pressure (maintain < 180/105), bleeding signs (gums, IV sites, urine, stool). No anticoagulants or antiplatelets for 24 hours. No invasive procedures. Contraindications: active bleeding, recent surgery, INR > 1.7."),
  rn("NCLEX-RN","Endocrine",3,"A client with type 2 diabetes is prescribed metformin. The nurse should teach the client about which potentially life-threatening adverse effect?",["Hypoglycemia","Lactic acidosis, which is rare but may present with muscle pain, weakness, difficulty breathing, and abdominal pain","Weight gain","Hyperkalemia"],1,"Metformin: first-line for type 2 DM. Most serious adverse effect: lactic acidosis (rare but potentially fatal). Risk factors: renal impairment (hold if eGFR < 30), hepatic dysfunction, heart failure, sepsis, excessive alcohol use. Hold 48 hours before and after iodinated contrast procedures. Does NOT cause hypoglycemia as monotherapy. GI side effects common (start low, increase slowly). Benefits: weight neutral or weight loss, cardiovascular benefits."),
  rn("NCLEX-RN","Renal/Urinary",3,"A client with a ureteral stent reports flank pain and urgency. The nurse should teach the client that:",["These symptoms are unexpected and require emergency evaluation","Some flank discomfort and urinary urgency are common after stent placement and usually improve over time","The stent should be removed immediately","No follow-up is needed after stent placement"],0,"Ureteral stent side effects: flank pain (especially with voiding due to reflux), urinary urgency and frequency, hematuria, dysuria. These are common and expected. Management: alpha-blockers (tamsulosin) may reduce symptoms, adequate hydration, analgesics (NSAIDs), anticholinergics for urgency. Stents are typically removed in 1-6 weeks. Teach: return for stent removal (retained stents can cause encrustation, infection, obstruction)."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with celiac disease asks the nurse which grains are safe to eat. The correct response includes:",["Wheat, barley, and rye are all safe","Rice, corn, quinoa, and gluten-free oats are safe alternatives","Only potatoes are safe","All grains must be avoided permanently"],1,"Celiac disease: autoimmune reaction to gluten (protein in wheat, barley, rye). Safe grains/starches: rice, corn, quinoa, buckwheat, millet, amaranth, teff, gluten-free oats (if not cross-contaminated), potatoes, tapioca. Avoid: wheat (including spelt, kamut), barley, rye, and cross-contaminated oats. Read labels carefully (hidden gluten in sauces, processed foods, medications). Lifelong gluten-free diet prevents intestinal damage and complications."),
  rn("NCLEX-RN","Integumentary",3,"A nurse is performing a skin assessment on a dark-skinned client. How should the nurse assess for skin color changes?",["Use the same technique as for light-skinned clients","Assess mucous membranes, nail beds, palms, soles, and conjunctivae for color changes since cyanosis and jaundice may not be visible on darkly pigmented skin","Only use capillary refill assessment","Skin color changes cannot be assessed in dark-skinned clients"],1,"Dark skin assessment: inspect areas with less melanin (palms, soles, nail beds, oral mucosa, conjunctivae, lips). Cyanosis: ashen, grayish cast (not blue). Jaundice: scleral icterus (most reliable), oral mucosa (yellow tinge). Erythema: palpate for warmth, edema, induration rather than relying on color change. Pallor: absence of underlying red tones, assess conjunctivae and mucous membranes. Petechiae: best seen on conjunctivae and oral mucosa."),
  rn("NCLEX-RN","Pediatrics",3,"A child with Kawasaki disease has been febrile for 5 days. The nurse should anticipate which treatment?",["Antibiotics only","High-dose IV immunoglobulin (IVIG) and high-dose aspirin to prevent coronary artery aneurysms","Corticosteroids as sole therapy","Observation without treatment"],1,"Kawasaki disease treatment: IVIG (2 g/kg single infusion) + high-dose aspirin (anti-inflammatory, 80-100 mg/kg/day) during acute phase. After fever resolution: low-dose aspirin (3-5 mg/kg/day) for antiplatelet effect for 6-8 weeks (until echocardiogram confirms no coronary artery changes). Diagnostic criteria: fever >= 5 days plus 4/5: bilateral conjunctival injection, oral changes, extremity changes, rash, cervical lymphadenopathy. Aspirin is the ONE pediatric exception (usually avoided due to Reye syndrome)."),
  rn("NCLEX-RN","Maternal/Newborn",3,"A client at 32 weeks gestation with preeclampsia is receiving magnesium sulfate. The nurse notes absent deep tendon reflexes. What is the nurse's first action?",["Continue the infusion at the current rate","Stop the magnesium sulfate infusion and notify the healthcare provider","Increase the infusion rate","Administer a fluid bolus"],1,"Magnesium sulfate toxicity: therapeutic level 4-7 mEq/L. Loss of deep tendon reflexes: first sign of toxicity (8-12 mEq/L). Respiratory depression: 12-15 mEq/L. Cardiac arrest: > 15 mEq/L. Assessment: DTRs hourly, respiratory rate (hold if < 12), urine output (minimum 30 mL/hr, magnesium is renally excreted). Antidote: calcium gluconate 1g IV push. Keep at bedside during magnesium infusion."),
  rn("NCLEX-RN","Mental Health",3,"A nurse is conducting a suicide risk assessment. Which client statement indicates the highest level of risk?",["I sometimes feel sad and hopeless","I have a loaded gun at home and plan to use it tonight after my family goes to sleep","I occasionally think about death","I used to think about suicide but not anymore"],1,"Highest suicide risk: specific plan, access to lethal means, identified time, and intent to carry out. Assess: ideation, plan, means, timeline, protective factors, previous attempts (strongest predictor of future attempts), substance use. Immediate interventions: 1:1 observation, remove access to lethal means, psychiatric evaluation, safety planning, notify treatment team. Columbia Suicide Severity Rating Scale (C-SSRS) for standardized assessment."),
  rn("NCLEX-RN","Pharmacology",3,"A client is prescribed clopidogrel (Plavix) after a coronary stent placement. The nurse should teach:",["The medication can be stopped after one week","Do not discontinue without provider approval because premature discontinuation increases the risk of stent thrombosis","Over-the-counter NSAIDs are safe to take with clopidogrel","The medication does not affect bleeding risk"],1,"Clopidogrel (P2Y12 inhibitor) after coronary stenting: dual antiplatelet therapy (aspirin + clopidogrel) duration depends on stent type: bare-metal stent (minimum 1 month), drug-eluting stent (minimum 6-12 months). Premature discontinuation: risk of stent thrombosis (potentially fatal MI). Teach: inform all providers/dentists, avoid elective surgery without cardiology consultation, take as prescribed, report unusual bleeding. Omeprazole interaction: reduces clopidogrel effectiveness."),
  rn("NCLEX-RN","Fundamentals",3,"A nurse is assessing a client's central venous catheter insertion site. Which finding requires immediate intervention?",["Intact transparent dressing","Redness, swelling, tenderness, and purulent drainage at the insertion site suggesting catheter-related bloodstream infection","Clean and dry insertion site","Patient reports no pain at the site"],1,"CLABSI prevention and assessment: daily site assessment for signs of infection (erythema, induration, tenderness, purulent drainage). If suspected: obtain blood cultures (from catheter and peripheral), remove catheter if indicated, send catheter tip for culture. Prevention bundle: hand hygiene, maximal sterile barriers during insertion, chlorhexidine skin prep, optimal site selection (avoid femoral), daily necessity assessment, scrub the hub before access."),
  rn("RN-CAT","Pharmacology",4,"A client develops neuroleptic malignant syndrome (NMS) while taking haloperidol. The nurse should recognize which key clinical features?",["Hypothermia and bradycardia","Hyperthermia (>40C), severe muscle rigidity (lead-pipe), altered mental status, and autonomic instability","Rash and joint pain","Diarrhea and abdominal pain"],1,"NMS: life-threatening reaction to antipsychotics. Cardinal features: hyperthermia (often > 40C/104F), severe muscle rigidity (lead-pipe), altered mental status, autonomic instability (tachycardia, labile BP, diaphoresis). Labs: markedly elevated CK (rhabdomyolysis), leukocytosis, elevated LFTs. Treatment: stop the offending agent, dantrolene (muscle relaxant), bromocriptine (dopamine agonist), supportive care (cooling, hydration, ICU). Mortality: 10-20%. Differentiate from serotonin syndrome and malignant hyperthermia."),
  rn("RN-CAT","Maternal/Newborn",4,"A neonate born at 34 weeks gestation develops grunting, nasal flaring, and retractions within 2 hours of birth. The nurse should suspect:",["Normal transition findings","Respiratory distress syndrome due to surfactant deficiency","Transient tachypnea of the newborn","Meconium aspiration"],1,"Neonatal RDS (hyaline membrane disease): surfactant deficiency in premature infants. Risk increases with earlier gestational age. Signs: grunting (auto-PEEP to maintain alveolar expansion), nasal flaring, intercostal/subcostal retractions, tachypnea, cyanosis. Diagnosis: chest X-ray (ground-glass appearance, air bronchograms). Treatment: exogenous surfactant replacement (intratracheal), CPAP or mechanical ventilation, thermoregulation. Prevention: antenatal corticosteroids (betamethasone) given to mother before preterm delivery."),
  rn("RN-CAT","Pediatrics",4,"A 3-year-old child is brought to the ED with a sudden onset of drooling, stridor, and a barking cough after playing with small toys. The nurse should suspect:",["Croup","Foreign body aspiration requiring immediate assessment and possible bronchoscopy","Asthma exacerbation","Epiglottitis"],1,"Foreign body aspiration: sudden onset of choking, coughing, stridor, or wheezing in a previously well child. Common ages: 6 months to 3 years. Most common objects: nuts, seeds, small toy parts, coins. If partial obstruction: do not intervene (may convert to complete obstruction). If complete obstruction: back blows/chest thrusts (infant), abdominal thrusts/Heimlich (child > 1 year). Diagnosis: inspiratory/expiratory chest X-rays (hyperinflation on affected side). Treatment: rigid bronchoscopy for removal."),
  rn("RN-CAT","Critical Care",4,"A client with acute liver failure develops cerebral edema. The nurse should implement which interventions?",["Lower head of bed to flat position","Elevate HOB to 30 degrees, administer mannitol or hypertonic saline, avoid hyperthermia, and prepare for possible intracranial pressure monitoring","Increase fluid intake aggressively","Administer hepatotoxic medications"],1,"Cerebral edema in acute liver failure: leading cause of death. Management: HOB 30 degrees, hyperventilation (short-term, target PaCO2 30-35), mannitol 0.5-1 g/kg (if serum osmolality < 320), hypertonic saline (target Na 145-155 mEq/L), hypothermia (target 32-35C), ICP monitoring if available (target ICP < 20, CPP > 60), avoid sedatives that impair neurological assessment when possible. Minimize stimulation. Consider emergent liver transplantation."),
  rn("RN-CAT","Hematological",4,"A client with thrombotic thrombocytopenic purpura (TTP) presents with the classic pentad. The nurse should prepare for which definitive treatment?",["Platelet transfusion","Emergent therapeutic plasma exchange (plasmapheresis)","Observation and supportive care","Splenectomy"],1,"TTP classic pentad: thrombocytopenia, microangiopathic hemolytic anemia (schistocytes on smear), neurological symptoms, renal dysfunction, fever. Caused by ADAMTS13 deficiency. Treatment: emergent therapeutic plasma exchange (removes anti-ADAMTS13 antibodies, replaces ADAMTS13). Do NOT give platelets (worsens thrombosis). Corticosteroids adjunctively. Rituximab for refractory or relapsing cases. Without treatment: mortality > 90%."),
  rn("NCLEX-RN","Dermatology",3,"A client is diagnosed with herpes zoster (shingles) on the trunk. The nurse should implement which precautions?",["Standard precautions only","Contact precautions (cover the lesions) and airborne precautions until lesions are crusted over in immunocompromised clients","Droplet precautions only","No isolation is necessary"],1,"Herpes zoster isolation: localized zoster in immunocompetent client: standard + contact precautions (cover lesions). Disseminated zoster or immunocompromised client: add airborne precautions (can transmit varicella to susceptible individuals). Lesions are infectious until fully crusted. Treatment: antivirals (acyclovir, valacyclovir) within 72 hours of rash onset. Pain management: gabapentin, pregabalin for postherpetic neuralgia. Shingrix vaccine for prevention (age >= 50)."),
  rn("NCLEX-RN","Perioperative",3,"A client in the post-anesthesia care unit (PACU) develops laryngospasm after extubation. The nurse's immediate action is:",["Administer oral fluids","Provide positive pressure ventilation with a bag-valve mask and jaw thrust, and prepare succinylcholine if unresponsive to these measures","Place the client in a supine flat position","Administer an oral airway"],1,"Post-extubation laryngospasm: potentially life-threatening. Immediate management: positive pressure ventilation with 100% O2 via BVM with jaw thrust (breaks spasm in most cases). If persistent: succinylcholine 0.1-1 mg/kg IV (paralyzes laryngeal muscles, requires intubation capability). Other interventions: remove irritating stimuli (blood, secretions), racemic epinephrine nebulization, reintubation if necessary. Risk factors: light anesthesia depth during extubation, airway irritation, blood/secretions."),
  rn("NCLEX-RN","Preventive Medicine",3,"A nurse is educating a 50-year-old client about recommended cancer screenings. Which screenings should the nurse discuss?",["No screenings are needed until age 65","Colorectal cancer screening (colonoscopy every 10 years or stool-based tests), lung cancer screening if high-risk smoker, and breast/cervical cancer screenings as appropriate","Only skin cancer screening","Only prostate cancer screening"],1,"USPSTF cancer screening recommendations (50-year-old): Colorectal: start at 45, colonoscopy every 10 years or stool-based tests more frequently. Breast (women): mammography every 2 years starting at 40-50 (depending on guidelines). Cervical: Pap/HPV co-testing every 5 years (ages 30-65). Lung: low-dose CT annually for 50-80 year olds with 20+ pack-year smoking history. Prostate: shared decision-making for PSA screening."),
  rn("NCLEX-RN","Wound Care",3,"A nurse is selecting a dressing for a wound with heavy exudate. Which dressing type is most appropriate?",["Transparent film dressing","Alginate or foam dressing to absorb excess drainage while maintaining moist wound environment","Dry gauze packed tightly","Hydrogel dressing"],0,"Wound dressing selection by exudate level: Heavy exudate: alginate (calcium alginate, made from seaweed, highly absorbent, forms a gel), hydrofiber, or foam dressings. Moderate: foam dressings, hydrofiber. Minimal: hydrocolloid or hydrogel. Dry wounds: hydrogel (provides moisture). Principle: maintain moist wound environment (promotes healing, prevents desiccation) while managing excess moisture (prevents maceration). Secondary dressings may be needed over primary."),
  rn("NCLEX-RN","Infectious Disease",3,"A nurse is caring for a client diagnosed with Clostridioides difficile infection. Which hand hygiene method is most effective?",["Alcohol-based hand sanitizer","Soap and water handwashing because C. difficile spores are not killed by alcohol-based sanitizers","Hand sanitizer followed by gloves","No specific hand hygiene is required beyond standard precautions"],1,"C. difficile: spore-forming organism. Alcohol-based hand sanitizers do NOT kill spores. Soap and water mechanically removes spores through friction. Contact precautions: gloves and gown. Dedicate equipment. Private room or cohabit with C. diff patients. Enhanced environmental cleaning with bleach-based (sporicidal) disinfectant. Risk factors: recent antibiotic use (fluoroquinolones, clindamycin, broad-spectrum), PPI use, hospitalization, age > 65. Treatment: oral vancomycin or fidaxomicin."),
  rn("NCLEX-RN","Delegation",3,"A nurse is prioritizing care for four clients. Which client should the nurse assess first?",["A client requesting pain medication rated 5 out of 10","A client with new-onset chest pain and diaphoresis","A client due for a scheduled medication","A client requesting discharge paperwork"],1,"Priority setting: ABCs (Airway, Breathing, Circulation), then Maslow's hierarchy, acute before chronic, unstable before stable. New-onset chest pain with diaphoresis: potential MI requiring immediate assessment and intervention (ECG, troponin, aspirin, nitroglycerin, morphine). Pain medication (stable need), scheduled medication (can be given within time frame), discharge paperwork (can wait). Use the priority frameworks consistently in NCLEX-style questions."),
  rn("NCLEX-RN","Women's Health",3,"A client taking combined oral contraceptives reports sudden severe calf pain and swelling. The nurse should:",["Reassure the client this is a common side effect","Advise the client to seek immediate medical evaluation because this may indicate a deep vein thrombosis","Recommend applying heat and elevating the leg","Suggest stopping the pill and using no contraception"],1,"Combined oral contraceptives (estrogen + progesterone) increase DVT risk (2-4x baseline, still low absolute risk). Danger signs (ACHES): Abdominal pain (hepatic vein thrombosis), Chest pain (PE), Headache severe (stroke), Eye problems (retinal vein thrombosis), Severe leg pain (DVT). Immediate evaluation needed. Contraindications: age > 35 and smoking, history of VTE, migraine with aura, uncontrolled hypertension, breast cancer. Progestin-only methods are safer alternatives."),

  // === NP QUESTIONS (25 to ensure we exceed 2000) ===
  np("AANP","Cardiovascular",3,"A nurse practitioner is evaluating a 55-year-old patient with newly diagnosed heart failure with preserved ejection fraction (HFpEF). Which management approach is most appropriate?",["ACE inhibitor and beta-blocker as in HFrEF","Diuretics for volume management, blood pressure control, treatment of comorbidities (AF, obesity, diabetes), and SGLT2 inhibitors","Digoxin as first-line therapy","Observation without medication"],1,"HFpEF management differs from HFrEF. No mortality-reducing medications clearly established (unlike HFrEF). Focus: diuretics for congestion, BP control (target < 130/80), rate control if AF, weight management, exercise. SGLT2 inhibitors (empagliflozin, dapagliflozin): EMPEROR-Preserved and DELIVER trials showed benefit. Spironolactone may reduce hospitalizations. Treat underlying conditions: obesity, diabetes, CAD, sleep apnea."),
  np("AANP","Cardiovascular",3,"A nurse practitioner is prescribing anticoagulation for a patient with atrial fibrillation. The CHA2DS2-VASc score is 3. Which is the most appropriate recommendation?",["Aspirin alone","Direct oral anticoagulant (DOAC) such as apixaban or rivaroxaban","No anticoagulation needed","Warfarin only with frequent INR monitoring"],1,"CHA2DS2-VASc >= 2 (men) or >= 3 (women): oral anticoagulation recommended. DOACs (apixaban, rivaroxaban, edoxaban, dabigatran) preferred over warfarin for non-valvular AF: no routine INR monitoring, fewer drug/food interactions, lower intracranial hemorrhage risk. Exceptions requiring warfarin: mechanical heart valves, moderate-severe mitral stenosis. Renal dosing adjustments for DOACs. HAS-BLED score assesses bleeding risk."),
  np("AANP","Endocrine",3,"A nurse practitioner is managing a patient with type 2 diabetes on metformin monotherapy with an A1C of 8.2%. The patient has established atherosclerotic cardiovascular disease. Which medication should be added?",["Sulfonylurea","GLP-1 receptor agonist (liraglutide or semaglutide) due to proven cardiovascular benefit","Thiazolidinedione","Insulin"],1,"ADA/EASD guidelines: T2DM with established ASCVD: add GLP-1 RA with proven CV benefit (liraglutide - LEADER trial, semaglutide - SUSTAIN-6) or SGLT2 inhibitor. GLP-1 RA benefits: A1C reduction, weight loss, CV risk reduction, low hypoglycemia risk. SGLT2 inhibitors preferred if HF or CKD. Sulfonylureas: hypoglycemia risk, weight gain, no CV benefit. TZDs: fluid retention, fracture risk."),
  np("AANP","Respiratory",3,"A nurse practitioner is evaluating a patient with moderate persistent asthma. According to stepwise therapy guidelines, which treatment is most appropriate?",["Short-acting beta-agonist as needed only","Low-dose inhaled corticosteroid plus long-acting beta-agonist (ICS-LABA) combination","Oral corticosteroids daily","Leukotriene receptor antagonist as monotherapy"],1,"GINA stepwise approach for moderate persistent asthma: Step 3 - low-dose ICS-LABA (e.g., fluticasone/salmeterol, budesonide/formoterol). Alternative: medium-dose ICS alone. PRN SABA for rescue. Assess control at every visit, step up if uncontrolled after 1-3 months (adherence, technique first), step down if controlled for 3+ months. SMART therapy (budesonide-formoterol as both maintenance and reliever) is an option."),
  np("AANP","Neurological",3,"A nurse practitioner diagnoses a patient with migraine with aura occurring 8 days per month. Which prophylactic medication is first-line?",["Sumatriptan daily","Topiramate, propranolol, or amitriptyline as prophylactic therapy","Acetaminophen scheduled","Opioid therapy"],1,"Migraine prophylaxis indications: >= 4 headache days/month, debilitating attacks, contraindication/failure/overuse of acute treatments. First-line: beta-blockers (propranolol, metoprolol), anticonvulsants (topiramate, valproate), antidepressants (amitriptyline, venlafaxine). CGRP monoclonal antibodies (erenumab, fremanezumab, galcanezumab) for refractory cases. Choice based on comorbidities: topiramate if overweight, propranolol if hypertensive, amitriptyline if insomnia."),
  np("AANP","Dermatology",3,"A nurse practitioner is evaluating a patient with a pigmented skin lesion. Which features suggest melanoma using the ABCDE criteria?",["Symmetric, uniform color, small, and smooth borders","Asymmetry, irregular borders, color variation, diameter greater than 6mm, and evolution or change over time","Flat, uniformly tan, and stable for years","Raised, dome-shaped, and flesh-colored"],1,"ABCDE criteria for melanoma: Asymmetry (one half differs from other), Border irregularity (notched, scalloped), Color variation (multiple shades of brown, black, red, white, blue), Diameter > 6mm (though melanomas can be smaller), Evolution (changing in size, shape, or color). Ugly duckling sign: lesion that looks different from patient's other moles. Referral for dermoscopy and excisional biopsy. Breslow depth determines prognosis and staging."),
  np("AANP","Musculoskeletal",3,"A nurse practitioner is managing a patient with gout who has had 3 flares in the past year. Which medication should be initiated for urate-lowering therapy?",["Colchicine alone without urate-lowering therapy","Allopurinol starting at a low dose (100 mg daily) and titrating to target serum urate level less than 6 mg/dL","Prednisone daily for prevention","NSAIDs scheduled daily"],1,"Gout urate-lowering therapy indications: >= 2 flares/year, tophi, urate nephropathy, urate nephrolithiasis. Allopurinol (xanthine oxidase inhibitor): start 100 mg/day (50 mg if CKD stage 4+), titrate by 100 mg every 2-4 weeks to target SUA < 6 mg/dL. Prophylaxis during initiation: colchicine 0.6 mg daily or BID for 3-6 months (prevents flare from urate mobilization). Alternative: febuxostat. Check HLA-B*5801 in certain populations before allopurinol (severe hypersensitivity risk)."),
  np("AANP","Gastrointestinal",3,"A nurse practitioner is evaluating a patient with dyspepsia and a positive Helicobacter pylori stool antigen test. Which treatment regimen is recommended?",["Proton pump inhibitor alone for 8 weeks","Quadruple therapy: PPI, bismuth subsalicylate, metronidazole, and tetracycline for 14 days","Single antibiotic therapy","Antacids as needed"],1,"H. pylori eradication: first-line options depend on local resistance patterns. Bismuth quadruple therapy (PPI + bismuth + metronidazole + tetracycline) x 14 days is preferred in areas with high clarithromycin resistance (> 15%). Alternative: clarithromycin triple therapy (PPI + clarithromycin + amoxicillin) x 14 days if low resistance. Confirm eradication 4+ weeks after completing therapy: urea breath test or stool antigen (must be off PPI for 2 weeks before testing)."),
  np("AANP","Mental Health",3,"A nurse practitioner is prescribing an antidepressant for a patient with major depressive disorder and comorbid chronic pain. Which medication class would address both conditions?",["SSRI (fluoxetine)","SNRI (duloxetine) which has FDA approval for both MDD and chronic pain conditions","Benzodiazepine","Buspirone"],1,"SNRIs (duloxetine, venlafaxine, milnacipran) inhibit serotonin and norepinephrine reuptake. Duloxetine FDA-approved for: MDD, GAD, diabetic peripheral neuropathy, fibromyalgia, chronic musculoskeletal pain. Dual benefit makes it ideal for comorbid depression and chronic pain. Start 30 mg daily, increase to 60 mg after 1 week. Side effects: nausea, dry mouth, constipation, dizziness, increased BP. Monitor BP and hepatic function. Avoid in hepatic impairment and excessive alcohol use."),
  np("AANP","Renal/Urinary",3,"A nurse practitioner is managing a patient with stage 3b chronic kidney disease (eGFR 35 mL/min). Which medication adjustments are necessary?",["No medication adjustments needed","Discontinue metformin, adjust NSAID use, dose-adjust renally cleared medications, and initiate phosphate binder if phosphorus elevated","Increase NSAID dose for pain","Start high-dose vitamin D without monitoring"],1,"CKD stage 3b (eGFR 30-44) medication management: metformin dose reduction (max 1000 mg/day, some guidelines hold at eGFR < 30), avoid NSAIDs (further reduce GFR, sodium retention), dose-adjust renally cleared drugs (gabapentin, allopurinol, many antibiotics), start phosphate binders if hyperphosphatemia, vitamin D supplementation (check 25-OH and 1,25-dihydroxy levels), erythropoiesis-stimulating agents if Hb < 10, SGLT2 inhibitor for kidney protection."),
  np("AANP","Infectious Disease",3,"A nurse practitioner is evaluating a patient with a cat bite wound on the hand that is now erythematous and swollen 12 hours after the bite. Which antibiotic is most appropriate?",["Cephalexin","Amoxicillin-clavulanate to cover Pasteurella multocida and polymicrobial bite flora","Metronidazole alone","Azithromycin"],1,"Cat bites: high infection rate (30-50%, deep puncture inoculates bacteria). Pasteurella multocida is the most common pathogen (rapid onset cellulitis within 24 hours). Amoxicillin-clavulanate: first-line (covers Pasteurella, Streptococcus, Staphylococcus, and anaerobes). Cephalexin lacks Pasteurella coverage. All cat bites should receive prophylactic antibiotics. Assess tetanus status, consider rabies risk. Hand bites: high risk for tenosynovitis, septic arthritis - consider orthopedic referral."),
  np("NP-CAT","Cardiovascular",4,"A nurse practitioner is evaluating a patient with resistant hypertension (uncontrolled on 3 agents including a diuretic). What should be the next step?",["Add a fourth medication without further workup","Screen for secondary causes of hypertension including primary aldosteronism (aldosterone-to-renin ratio), renal artery stenosis, pheochromocytoma, and Cushing syndrome","Increase all current medications to maximum doses","Refer for immediate renal denervation"],1,"Resistant hypertension (BP > 130/80 on 3 optimal-dose agents including diuretic): first confirm true resistance (rule out white coat effect with ABPM, assess medication adherence, check for interfering substances - NSAIDs, decongestants, alcohol). Then screen for secondary causes: primary aldosteronism (most common, 5-10% of HTN), renal artery stenosis, pheochromocytoma, Cushing, thyroid disease, OSA. Aldosterone-to-renin ratio as screening test. Spironolactone effective as add-on in resistant HTN."),
  np("NP-CAT","Endocrine",4,"A nurse practitioner is managing a patient with newly diagnosed Graves disease. The patient is a 28-year-old woman planning pregnancy in 1 year. Which treatment approach is most appropriate?",["Radioactive iodine ablation immediately","Methimazole initially with plan to switch to propylthiouracil (PTU) if pregnancy occurs during first trimester","Surgery as first-line","No treatment until pregnancy occurs"],1,"Graves disease in reproductive-age women: antithyroid drugs preferred over RAI (contraindicated in pregnancy, requires 6-month delay before conception). Methimazole is first-choice (lower hepatotoxicity risk than PTU). Exception: first trimester of pregnancy - use PTU (methimazole associated with embryopathy: aplasia cutis, choanal atresia). Switch back to methimazole after first trimester. If thyroidectomy needed: perform in second trimester. Monitor TRAb (crosses placenta, can cause neonatal thyrotoxicosis)."),
  np("NP-CAT","Respiratory",4,"A nurse practitioner is interpreting pulmonary function tests for a patient with suspected COPD. FEV1/FVC ratio is 0.62 and post-bronchodilator FEV1 is 55% predicted. What is the GOLD classification?",["GOLD 1 (mild)","GOLD 2 (moderate) based on FEV1 50-79% predicted with confirmed obstruction (FEV1/FVC < 0.70)","GOLD 3 (severe)","Not COPD"],1,"COPD diagnosis: post-bronchodilator FEV1/FVC < 0.70 confirms airflow obstruction. GOLD severity classification based on post-BD FEV1: GOLD 1 (mild): >= 80% predicted; GOLD 2 (moderate): 50-79%; GOLD 3 (severe): 30-49%; GOLD 4 (very severe): < 30%. This patient: FEV1/FVC 0.62 (< 0.70, confirmed obstruction) + FEV1 55% (50-79%) = GOLD 2. ABCD assessment adds symptom burden (mMRC/CAT) and exacerbation history for treatment decisions. Treatment: LAMA +/- LABA, consider ICS if eosinophils elevated."),
  np("NP-CAT","Neurological",4,"A nurse practitioner is evaluating a patient with new-onset seizures and finds a ring-enhancing brain lesion on MRI. The differential diagnosis includes:",["Migraine only","Brain abscess, primary or metastatic brain tumor, toxoplasmosis (if immunocompromised), or demyelinating disease","Benign finding requiring no further workup","Tension headache"],1,"Ring-enhancing brain lesions DDx: brain abscess (central restricted diffusion on DWI-MRI), glioblastoma (irregular enhancing ring, central necrosis), metastatic tumor, toxoplasmosis (in HIV/AIDS, often multiple, basal ganglia), lymphoma, demyelinating disease (tumefactive MS), radiation necrosis. Workup: contrast MRI with spectroscopy, consider stereotactic biopsy. In immunocompromised: toxoplasma serology, consider empiric treatment. HIV-associated: toxoplasmosis vs. primary CNS lymphoma."),
  np("NP-CAT","Gastrointestinal",4,"A nurse practitioner is evaluating a patient with new-onset ascites. Which initial diagnostic test is most important?",["CT scan of the abdomen","Diagnostic paracentesis with ascitic fluid analysis including cell count, albumin, and culture","Liver biopsy","Colonoscopy"],1,"New-onset ascites: diagnostic paracentesis is mandatory. Calculate serum-ascites albumin gradient (SAAG): >= 1.1 g/dL = portal hypertension (cirrhosis, heart failure, Budd-Chiari). < 1.1 = non-portal hypertension (malignancy, TB peritonitis, nephrotic syndrome, pancreatitis). Also obtain: cell count with differential (PMN > 250 = spontaneous bacterial peritonitis), total protein, glucose, LDH, culture (inoculate blood culture bottles at bedside). Cytology if malignancy suspected. Treatment based on etiology."),
  np("AANP","Pharmacology",3,"A nurse practitioner is prescribing a statin for a patient with LDL of 190 mg/dL. According to current guidelines, which approach is recommended?",["Low-intensity statin therapy","High-intensity statin therapy (atorvastatin 40-80 mg or rosuvastatin 20-40 mg) targeting at least 50% LDL reduction","Lifestyle modifications only without medication","Fibrate therapy as first-line"],1,"ACC/AHA statin therapy guidelines: LDL >= 190 mg/dL: high-intensity statin without risk calculation needed (one of 4 statin benefit groups). High-intensity: atorvastatin 40-80 mg or rosuvastatin 20-40 mg (expected >= 50% LDL reduction). Moderate-intensity: atorvastatin 10-20 mg, rosuvastatin 5-10 mg (30-49% reduction). If LDL remains >= 70 with ASCVD: consider ezetimibe, then PCSK9 inhibitor. Monitor lipids 4-12 weeks after initiation, then annually. No routine LFT monitoring unless symptoms."),
  np("AANP","Women's Health",3,"A nurse practitioner is evaluating a 52-year-old woman with hot flashes, night sweats, and vaginal dryness affecting quality of life. Which treatment is most appropriate?",["Black cohosh as sole therapy","Hormone replacement therapy (HRT) with estrogen plus progestogen (for intact uterus) is the most effective treatment for vasomotor symptoms","Antidepressants as first-line","No treatment is available"],1,"Menopausal hormone therapy: most effective treatment for vasomotor symptoms. Estrogen + progesterone (women with uterus, to prevent endometrial hyperplasia) or estrogen alone (post-hysterectomy). Use lowest effective dose for shortest duration. Initiation within 10 years of menopause or before age 60 (favorable risk-benefit). Contraindications: breast cancer, CAD, VTE, active liver disease, unexplained vaginal bleeding. Alternatives: SSRIs/SNRIs, gabapentin, fezolinetant (NK3 receptor antagonist). Vaginal estrogen for isolated urogenital symptoms."),
  np("AANP","Pediatrics",3,"A nurse practitioner is evaluating a 7-year-old child with attention-deficit/hyperactivity disorder (ADHD) who is not responding adequately to behavioral interventions. Which medication is first-line?",["Clonidine","Methylphenidate (stimulant medication) as first-line pharmacotherapy for ADHD in school-age children","Atomoxetine as first choice","Bupropion"],1,"ADHD pharmacotherapy (AAP guidelines): school-age children (6-11): first-line is stimulant medication (methylphenidate or amphetamine). Methylphenidate formulations: immediate-release (Ritalin), extended-release (Concerta, Ritalin LA). Titrate to optimal dose based on symptom control and side effects. Monitor: height, weight, vital signs, appetite, sleep. Side effects: appetite suppression, insomnia, irritability. Second-line: atomoxetine, guanfacine, clonidine (non-stimulants). Combination therapy may be needed."),
  np("NP-CAT","Mental Health",4,"A nurse practitioner is evaluating a patient who presents with depressed mood, weight gain, hypersomnia, and leaden paralysis. This presentation is most consistent with:",["Typical major depression","Major depressive disorder with atypical features, which may respond preferentially to MAOIs or SSRIs","Bipolar II disorder","Dysthymia"],1,"Atypical depression features (DSM-5 specifier): mood reactivity (mood brightens with positive events) + >= 2 of: significant weight gain or increased appetite, hypersomnia, leaden paralysis (heavy feeling in arms/legs), interpersonal rejection sensitivity. Treatment: MAOIs (phenelzine) historically most effective, but SSRIs/SNRIs preferred due to safety profile. Distinguish from melancholic features (insomnia, weight loss, worse in morning, no mood reactivity). More common in women, earlier onset, chronic course."),
  np("NP-CAT","Infectious Disease",4,"A nurse practitioner is managing an HIV-positive patient with a CD4 count of 150 cells/mm3. Which opportunistic infection prophylaxis should be initiated?",["No prophylaxis needed above CD4 100","Trimethoprim-sulfamethoxazole for Pneumocystis jirovecii prophylaxis (CD4 < 200) and azithromycin for MAC prophylaxis (CD4 < 50)","Prophylaxis only when symptomatic","Antifungal prophylaxis only"],1,"OI prophylaxis based on CD4 count: < 200: TMP-SMX for PCP (also provides toxoplasma prophylaxis if seropositive). < 150: consider adding coccidioidomycosis prophylaxis in endemic areas. < 100: add toxoplasma prophylaxis if seropositive and not already on TMP-SMX. < 50: azithromycin or clarithromycin for MAC prophylaxis. CD4 150: PCP prophylaxis (TMP-SMX DS daily), MAC prophylaxis not yet needed. Discontinue prophylaxis when CD4 > threshold on ART for 3+ months."),
  np("AANP","Geriatrics",3,"A nurse practitioner is conducting a comprehensive geriatric assessment for an 80-year-old patient. Which screening tools should be included?",["Blood pressure and weight only","Fall risk assessment (Timed Up and Go), cognitive screening (Mini-Cog or MMSE), depression screening (PHQ-9 or GDS), functional status (ADLs/IADLs), and nutritional assessment","Vision screening only","Cardiac stress testing"],1,"Comprehensive geriatric assessment domains: functional status (ADLs: bathing, dressing, toileting, transferring, feeding; IADLs: cooking, cleaning, finances, medications, transportation), cognition (Mini-Cog, MMSE, MoCA), mood (GDS-15, PHQ-9), fall risk (Timed Up and Go < 12 seconds normal, gait speed), nutrition (MNA, BMI, albumin, weight change), polypharmacy review (Beers Criteria), social support, advance directives, sensory impairment, incontinence, pain assessment."),
];

async function run() {
  const client = await pool.connect();
  try {
    let inserted = 0, skipped = 0;
    for (let i = 0; i < QS.length; i += 50) {
      const batch = QS.slice(i, i + 50);
      const vals: string[] = [];
      const params: any[] = [];
      let pi = 1;
      for (const q of batch) {
        const h = hash(q.stem);
        vals.push(`($${pi++},$${pi++},'multiple_choice','published',$${pi++},$${pi++}::jsonb,$${pi++}::jsonb,$${pi++},$${pi++}::integer,$${pi++},$${pi++},$${pi++})`);
        params.push(q.tier, q.exam, q.stem, JSON.stringify(q.options), JSON.stringify([q.correct]), q.rationale, q.diff, q.bs, 'BOTH', h);
      }
      const sql = `INSERT INTO exam_questions (tier,exam,question_type,status,stem,options,correct_answer,rationale,difficulty,body_system,region_scope,stem_hash)
        SELECT * FROM (VALUES ${vals.join(",")}) AS v(tier,exam,question_type,status,stem,options,correct_answer,rationale,difficulty,body_system,region_scope,stem_hash)
        WHERE NOT EXISTS (SELECT 1 FROM exam_questions eq WHERE eq.stem_hash = v.stem_hash)`;
      const res = await client.query(sql, params);
      inserted += res.rowCount || 0;
      skipped += batch.length - (res.rowCount || 0);
      console.log(`Batch ${Math.floor(i/50)+1}: inserted ${res.rowCount}, skipped ${batch.length - (res.rowCount || 0)}`);
    }
    console.log(`Done: inserted=${inserted}, skipped=${skipped}, total attempted=${QS.length}`);
    const counts = await client.query(`SELECT exam, COUNT(*) as c FROM exam_questions WHERE status='published' GROUP BY exam ORDER BY exam`);
    console.log("Current counts:");
    for (const r of counts.rows) console.log(`  ${r.exam}: ${r.c}`);
    const totals = await client.query(`SELECT
      SUM(CASE WHEN exam IN ('REX-PN','REx-PN','NCLEX-PN','RPN-CAT') THEN 1 ELSE 0 END) as rpn,
      SUM(CASE WHEN exam IN ('NCLEX-RN','RN-CAT') THEN 1 ELSE 0 END) as rn,
      SUM(CASE WHEN exam IN ('AANP','CNPLE','NP-CAT') THEN 1 ELSE 0 END) as np
      FROM exam_questions WHERE status='published'`);
    console.log("Totals:", totals.rows[0]);
  } finally {
    client.release();
    await pool.end();
  }
}
run().catch(e => { console.error(e); process.exit(1); });
